    fn offset_reject_pending(
        expected_record: PlaceableCustomAppearanceUpdateAnchorRecord,
        insertion_origin: PlaceableCustomAppearanceUpdateInsertionOrigin,
    ) -> PendingPlaceableCustomAppearanceUpdate {
        PendingPlaceableCustomAppearanceUpdate {
            original_insert_offset: 0,
            anchor: PlaceableCustomAppearanceUpdateInsertionAnchor {
                original_record_offset: 0,
                original_record_end: 0,
                opcode: match expected_record {
                    PlaceableCustomAppearanceUpdateAnchorRecord::PlaceableAdd => b'A',
                    PlaceableCustomAppearanceUpdateAnchorRecord::NormalAppearanceUpdate
                    | PlaceableCustomAppearanceUpdateAnchorRecord::CustomAppearanceUpdate => b'U',
                },
                expected_record,
                fragment_bit_start: CNW_FRAGMENT_HEADER_BITS,
                fragment_bit_end: CNW_FRAGMENT_HEADER_BITS,
                source_appearance: LiveObjectPlaceableAppearance {
                    appearance: 0x0011,
                    resref: None,
                },
            },
            object_id: 0x8000_34D8,
            fragment_bit_cursor: CNW_FRAGMENT_HEADER_BITS,
            appearance: 0xFFFE,
            template_resref: *b"plc_custom_add\0\0",
            insertion_origin,
            insertion_carrier: None,
            insertion_target_unavailable_reason: None,
            anchor_rewrite_already_counted: false,
        }
    }

    fn synthetic_focus_pending(
        object_id: u32,
        original_insert_offset: usize,
    ) -> PendingPlaceableCustomAppearanceUpdate {
        PendingPlaceableCustomAppearanceUpdate {
            original_insert_offset,
            anchor: PlaceableCustomAppearanceUpdateInsertionAnchor {
                original_record_offset: original_insert_offset.saturating_sub(8),
                original_record_end: original_insert_offset,
                opcode: b'A',
                expected_record: PlaceableCustomAppearanceUpdateAnchorRecord::PlaceableAdd,
                fragment_bit_start: CNW_FRAGMENT_HEADER_BITS,
                fragment_bit_end: CNW_FRAGMENT_HEADER_BITS,
                source_appearance: LiveObjectPlaceableAppearance {
                    appearance: 0x0011,
                    resref: None,
                },
            },
            object_id,
            fragment_bit_cursor: CNW_FRAGMENT_HEADER_BITS,
            appearance: 0xFFFE,
            template_resref: *b"plc_custom_add\0\0",
            insertion_origin:
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddWithoutCarrier,
            insertion_carrier: None,
            insertion_target_unavailable_reason: None,
            anchor_rewrite_already_counted: false,
        }
    }

    #[test]
    fn synthetic_custom_placeable_batch_reject_focus_uses_final_offsets() {
        let low = synthetic_focus_pending(0x8000_3401, 10);
        let high = synthetic_focus_pending(0x8000_3402, 20);
        let emitted = vec![
            EmittedPlaceableCustomAppearanceUpdate {
                insert_offset: 20,
                sequence: 0,
                update: high,
                bytes_inserted: 5,
            },
            EmittedPlaceableCustomAppearanceUpdate {
                insert_offset: 10,
                sequence: 1,
                update: low,
                bytes_inserted: 5,
            },
        ];

        let before = focused_placeable_custom_appearance_update_batch_reject(9, &emitted)
            .expect("reject before staged bytes should still focus the first staged carrier");
        assert_eq!(
            before.kind,
            PlaceableCustomAppearanceUpdateBatchRejectFocusKind::BeforeSynthesizedUpdate
        );
        assert_eq!(before.insert_offset, 10);
        assert_eq!(before.update.object_id, 0x8000_3401);

        let inside = focused_placeable_custom_appearance_update_batch_reject(12, &emitted)
            .expect("reject inside staged bytes should focus that staged carrier");
        assert_eq!(
            inside.kind,
            PlaceableCustomAppearanceUpdateBatchRejectFocusKind::InsideSynthesizedUpdate
        );
        assert_eq!(inside.insert_offset, 10);
        assert_eq!(inside.record_end, 15);

        let between = focused_placeable_custom_appearance_update_batch_reject(24, &emitted)
            .expect("reject after lower staged bytes should focus the preceding carrier");
        assert_eq!(
            between.kind,
            PlaceableCustomAppearanceUpdateBatchRejectFocusKind::AfterSynthesizedUpdate
        );
        assert_eq!(between.insert_offset, 10);

        let after = focused_placeable_custom_appearance_update_batch_reject(30, &emitted)
            .expect("reject after all staged bytes should focus the nearest prior carrier");
        assert_eq!(
            after.kind,
            PlaceableCustomAppearanceUpdateBatchRejectFocusKind::AfterSynthesizedUpdate
        );
        assert_eq!(after.insert_offset, 25);
        assert_eq!(after.record_end, 30);
    }

    #[test]
    fn synthetic_custom_placeable_final_row_guard_uses_exact_writer_output() {
        let object_id = 0x8000_34D8u32;
        let target_resref = *b"plc_custom_add\0\0";
        let stale_resref = *b"plc_stale_add\0\0\0";
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&stale_resref);
        let fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let pending = synthetic_focus_pending(object_id, 0);
        let emitted = vec![EmittedPlaceableCustomAppearanceUpdate {
            insert_offset: 0,
            sequence: 0,
            update: pending,
            bytes_inserted: live.len(),
        }];

        let focus =
            invalid_synthesized_placeable_custom_appearance_update(&live, &fragment_bits, &emitted)
                .expect("parser-valid but stale-resref carrier must fail final writer proof");

        assert_eq!(
            focus.kind,
            PlaceableCustomAppearanceUpdateBatchRejectFocusKind::InsideSynthesizedUpdate
        );
        assert_eq!(focus.insert_offset, 0);
        assert_eq!(focus.record_end, live.len());
        assert_eq!(focus.update.object_id, object_id);
        assert_eq!(focus.update.template_resref, target_resref);

        live.splice(
            LEGACY_UPDATE_HEADER_BYTES + EE_UPDATE_APPEARANCE_WORD_READ_BYTES..live.len(),
            target_resref.iter().copied(),
        );
        assert!(
            invalid_synthesized_placeable_custom_appearance_update(
                &live,
                &fragment_bits,
                &emitted,
            )
            .is_none(),
            "the same U/09 row is accepted once the final bytes match the staged writer output"
        );
    }

    #[test]
    fn exact_placeable_update_rejects_fragment_cursor_past_valid_bits() {
        let object_id = 0x8000_34D8u32;
        let target_resref = *b"plc_custom_add\0\0";
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&target_resref);
        let fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];

        assert!(
            verified_placeable_update_exact_claim(
                &live,
                0,
                live.len(),
                &fragment_bits,
                CNW_FRAGMENT_HEADER_BITS,
            )
            .is_some(),
            "a no-fragment-bit U/09 custom appearance row may start exactly at the valid cursor"
        );
        assert!(
            verified_placeable_update_exact_claim(
                &live,
                0,
                live.len(),
                &fragment_bits,
                CNW_FRAGMENT_HEADER_BITS + 1,
            )
            .is_none(),
            "even zero-bit U/09 rows cannot start beyond the valid CNW fragment stream"
        );
    }

    #[test]
    fn synthetic_custom_placeable_update_exact_claim_requires_target_resref() {
        let object_id = 0x8000_35D1u32;
        let target_resref = *b"plc_exact_ok\0\0\0\0";
        let wrong_resref = *b"plc_exact_bad\0\0\0";
        let appearance = 0xFFFEu16;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&appearance.to_le_bytes());
        live.extend_from_slice(&target_resref);
        let fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];

        assert!(
            verified_synthesized_placeable_custom_appearance_update_exact_claim(
                &live,
                0,
                live.len(),
                &fragment_bits,
                CNW_FRAGMENT_HEADER_BITS,
                object_id,
                appearance,
                target_resref,
            ),
            "the synthetic U/09 row must exact-claim the inserted WORD+CResRef branch"
        );
        assert!(
            !verified_synthesized_placeable_custom_appearance_update_exact_claim(
                &live,
                0,
                live.len(),
                &fragment_bits,
                CNW_FRAGMENT_HEADER_BITS,
                object_id,
                appearance,
                wrong_resref,
            ),
            "a parser-valid custom row with the wrong CResRef is not the staged writer output"
        );
        assert!(
            !verified_synthesized_placeable_custom_appearance_update_exact_claim(
                &live,
                0,
                live.len(),
                &fragment_bits,
                CNW_FRAGMENT_HEADER_BITS + 1,
                object_id,
                appearance,
                target_resref,
            ),
            "the exact writer proof must retain the caller-owned fragment cursor"
        );
    }

    #[test]
    fn pending_synthesized_custom_placeable_update_records_offset_reject_classes() {
        let area_context = crate::translate::area::AreaPlaceableContext::default();
        let fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let edits = vec![LiveByteOffsetEdit {
            original_offset: 0,
            bytes_inserted: 0,
            bytes_removed: 1,
        }];

        let mut add_live = Vec::new();
        let mut add_summary = LiveObjectUpdateRewriteSummary::default();
        let add_result = apply_pending_placeable_custom_appearance_updates(
            &area_context,
            &mut add_live,
            &fragment_bits,
            &edits,
            vec![offset_reject_pending(
                PlaceableCustomAppearanceUpdateAnchorRecord::PlaceableAdd,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddWithoutCarrier,
            )],
            &mut add_summary,
        );

        assert_eq!(add_result, None);
        assert_eq!(
            add_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_planned,
            0,
            "offset rejects happen before a synthetic carrier is counted as planned"
        );
        assert_eq!(
            add_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_offset_insert_rejected,
            1
        );
        assert_eq!(
            add_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_offset_anchor_start_rejected,
            0
        );
        assert_eq!(
            add_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_offset_anchor_end_rejected,
            0
        );
        assert_synthesized_custom_carrier_offset_reject_classes(&add_summary, 1, 0, 0, 1);
        assert_eq!(add_live, Vec::<u8>::new());

        let mut normal_live = Vec::new();
        let mut normal_summary = LiveObjectUpdateRewriteSummary::default();
        let normal_result = apply_pending_placeable_custom_appearance_updates(
            &area_context,
            &mut normal_live,
            &fragment_bits,
            &edits,
            vec![offset_reject_pending(
                PlaceableCustomAppearanceUpdateAnchorRecord::NormalAppearanceUpdate,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddFollowingNormalRewriteTargetMismatch,
            )],
            &mut normal_summary,
        );

        assert_eq!(normal_result, None);
        assert_eq!(
            normal_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_offset_insert_rejected,
            1
        );
        assert_synthesized_custom_carrier_offset_reject_classes(&normal_summary, 0, 1, 0, 1);
        assert_eq!(normal_live, Vec::<u8>::new());

        let mut custom_live = Vec::new();
        let mut custom_summary = LiveObjectUpdateRewriteSummary::default();
        let custom_result = apply_pending_placeable_custom_appearance_updates(
            &area_context,
            &mut custom_live,
            &fragment_bits,
            &edits,
            vec![offset_reject_pending(
                PlaceableCustomAppearanceUpdateAnchorRecord::CustomAppearanceUpdate,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddFollowingCustomRewriteTargetMismatch,
            )],
            &mut custom_summary,
        );

        assert_eq!(custom_result, None);
        assert_eq!(
            custom_summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_offset_insert_rejected,
            1
        );
        assert_synthesized_custom_carrier_offset_reject_classes(&custom_summary, 0, 0, 1, 1);
        assert_eq!(custom_live, Vec::<u8>::new());
    }

    #[test]
    fn pending_synthesized_custom_placeable_update_records_emit_reject() {
        let object_id = 0x8000_34D8u32;
        let target_resref = *b"plc_custom_add\0\0";
        let area_context = crate::translate::area::AreaPlaceableContext::default();
        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot.
            true,  // useable.
            false, // trap disarmable.
            true,  // lockable.
            false, // locked.
            false, // unknown 0x1AC sibling.
            true,  // name-valid.
            false, // EE-only light/visual guard.
        ]);
        let original_live = live.clone();
        let mut summary = LiveObjectUpdateRewriteSummary::default();

        let result = apply_pending_placeable_custom_appearance_updates(
            &area_context,
            &mut live,
            &fragment_bits,
            &[],
            vec![PendingPlaceableCustomAppearanceUpdate {
                original_insert_offset: add_end,
                anchor: PlaceableCustomAppearanceUpdateInsertionAnchor {
                    original_record_offset: 0,
                    original_record_end: add_end,
                    opcode: b'A',
                    expected_record: PlaceableCustomAppearanceUpdateAnchorRecord::PlaceableAdd,
                    fragment_bit_start: CNW_FRAGMENT_HEADER_BITS,
                    fragment_bit_end: fragment_bits.len(),
                    source_appearance: LiveObjectPlaceableAppearance {
                        appearance: 0x0011,
                        resref: None,
                    },
                },
                object_id,
                fragment_bit_cursor: fragment_bits.len(),
                appearance: 0x0011,
                template_resref: target_resref,
                insertion_origin:
                    PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddWithoutCarrier,
                insertion_carrier: None,
                insertion_target_unavailable_reason: None,
                anchor_rewrite_already_counted: false,
            }],
            &mut summary,
        );

        assert_eq!(result, None);
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_planned,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_plan_anchor_rejected,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_emit_rejected,
            1
        );
        assert_eq!(
            live, original_live,
            "failed synthetic U/09 validation must not leave inserted bytes behind"
        );
    }

