    #[test]
    fn item_failure_source_window_keeps_focus_row_and_neighbors() {
        let mut live = Vec::new();
        live.extend_from_slice(&[b'U', DOOR_OBJECT_TYPE, 0x10, 0, 0, 0]);
        live.extend_from_slice(&0xFFFF_FFF7u32.to_le_bytes());
        live.extend_from_slice(&[b'A', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        live.extend_from_slice(&[b'U', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        live.extend_from_slice(&0xFFFF_FFF3u32.to_le_bytes());

        let rows = live_object_source_window_rows(&live, 16, 26, 2, 1);
        assert_eq!(rows.len(), 3);
        assert_eq!(rows[0].offset, 0);
        assert_eq!(rows[0].update_mask, Some(0xFFFF_FFF7));
        assert_eq!(rows[1].offset, 10);
        assert_eq!(rows[1].object_id, Some(0x0000_0020));
        assert_eq!(rows[2].offset, 16);
        assert_eq!(rows[2].record_end, 26);
        assert_eq!(rows[2].update_mask, Some(0xFFFF_FFF3));
    }

    #[test]
    fn item_failure_source_window_claims_show_cumulative_bit_cursor() {
        let mut live = Vec::new();
        live.extend_from_slice(&[b'D', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        live.extend_from_slice(&[b'U', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        live.extend_from_slice(&0x0000_0040u32.to_le_bytes());

        let rows = live_object_source_window_rows(&live, 6, 16, 1, 0);
        let fragment_bits = vec![false, false, false, true, false];
        let claims = live_object_source_window_row_bit_claims(
            &live,
            &rows,
            &fragment_bits,
            CNW_FRAGMENT_HEADER_BITS,
        );

        assert_eq!(claims.len(), 2);
        assert_eq!(claims[0].offset, 0);
        assert_eq!(claims[0].family, "delete");
        assert_eq!(claims[0].bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(claims[0].bit_end, Some(CNW_FRAGMENT_HEADER_BITS + 1));
        assert_eq!(claims[1].offset, 6);
        assert_eq!(claims[1].family, "item-update");
        assert_eq!(claims[1].bit_start, CNW_FRAGMENT_HEADER_BITS + 1);
        assert_eq!(claims[1].bit_end, Some(CNW_FRAGMENT_HEADER_BITS + 2));
    }

    #[test]
    fn source_window_claims_name_gui_inventory_and_world_status_rows() {
        let live = vec![b'G', b'Q', 0, b'W', 1, 2];
        let rows = live_object_source_window_rows(&live, 0, 3, 0, 1);
        let claims = live_object_source_window_row_bit_claims(
            &live,
            &rows,
            &[false, false, false],
            CNW_FRAGMENT_HEADER_BITS,
        );

        assert_eq!(claims.len(), 2);
        assert_eq!(claims[0].offset, 0);
        assert_eq!(claims[0].family, "live-gui");
        assert_eq!(claims[0].bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(claims[0].bit_end, Some(CNW_FRAGMENT_HEADER_BITS));
        assert_eq!(claims[1].offset, 3);
        assert_eq!(claims[1].family, "world-status");
        assert_eq!(claims[1].bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(claims[1].bit_end, Some(CNW_FRAGMENT_HEADER_BITS));

        let mut inventory = vec![b'I'];
        inventory.extend_from_slice(&0xFFFF_FFFEu32.to_le_bytes());
        inventory.extend_from_slice(&0x0400u16.to_le_bytes());
        inventory.push(0);
        inventory.push(1);
        inventory.push(0x10);
        let inventory_row = LiveObjectSourceWindowRow {
            offset: 0,
            record_end: inventory.len(),
            opcode: b'I',
            marker: inventory[1],
            object_id: None,
            update_mask: None,
        };

        assert_eq!(
            live_object_source_window_row_bit_claim(
                &inventory,
                &inventory_row,
                &[false, false, false, true],
                CNW_FRAGMENT_HEADER_BITS,
            ),
            Some(("inventory", CNW_FRAGMENT_HEADER_BITS + 1)),
            "a verified inventory row owns its set-slot BOOL in the source-window diagnostic"
        );
    }

