    #[test]
    fn item_create_rewrite_reports_typed_source_bit_claim_for_ledger() {
        let mut live = diagnostic_model_type2_typed_item_create_record();
        let mut record_end = live.len();
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let source_record_bits = [false, false, true, false, false];
        let following_record_bits = [true, false];
        fragment_bits.extend_from_slice(&source_record_bits);
        fragment_bits.extend_from_slice(&following_record_bits);
        let add_start_bit_cursor = CNW_FRAGMENT_HEADER_BITS;

        let rewrite = appearance::insert_ee_item_create_extras_for_ee(
            &mut live,
            2,
            &mut record_end,
            &mut fragment_bits,
            add_start_bit_cursor,
        )
        .expect("typed A/6 item-create rewrite should expose its bit claim");

        assert_eq!(rewrite.bits_inserted, 1);
        assert_eq!(
            rewrite.source_fragment_bits_consumed,
            Some(source_record_bits.len())
        );
        assert_eq!(
            rewrite.emitted_fragment_bits_consumed,
            Some(source_record_bits.len() + rewrite.bits_inserted)
        );

        let mut emitted_cursor = add_start_bit_cursor;
        assert!(add::advance_verified_add_record(
            &live,
            0,
            record_end,
            &fragment_bits,
            &mut emitted_cursor,
        ));
        assert_eq!(
            emitted_cursor,
            add_start_bit_cursor + rewrite.emitted_fragment_bits_consumed.unwrap()
        );
        assert_eq!(
            &fragment_bits[emitted_cursor..],
            &following_record_bits,
            "the inserted EE active-property bit must stay inside A/6"
        );

        let mut ledger = LiveObjectRewriteBitLedger::new();
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end,
                emitted_bit_start: add_start_bit_cursor,
                emitted_bit_end: emitted_cursor,
                bits_inserted: rewrite.bits_inserted,
                bits_removed: rewrite.bits_removed,
                family: "item-create-rewrite",
            },
        ));

        let entry = ledger
            .entries()
            .last()
            .expect("ledger should contain the item-create row");
        assert_eq!(entry.family, "item-create-rewrite");
        assert_eq!(entry.source_bit_start, add_start_bit_cursor);
        assert_eq!(
            entry.source_bit_end,
            add_start_bit_cursor + source_record_bits.len()
        );
        assert_eq!(entry.emitted_bit_end, emitted_cursor);
        let shifted_candidate = ledger
            .gap_before_cursor(emitted_cursor + 2)
            .expect("shifted U/6 neighbor should be classified after A/6");
        assert_eq!(shifted_candidate.previous_family, "item-create-rewrite");
        assert_eq!(shifted_candidate.source_relation, "unowned-source-gap");
        assert_eq!(shifted_candidate.source_gap_bits, 2);
    }

    #[test]
    fn item_unowned_neighbor_retains_focus_cursor_failure() {
        let mut live = diagnostic_model_type2_typed_item_create_record();
        let item_offset = live.len();
        live.extend_from_slice(&diagnostic_full_item_update_live_bytes());

        let add_start_bit_cursor = CNW_FRAGMENT_HEADER_BITS;
        let add_source_bits = [false, false, true, false, false];
        let add_emitted_bits = [false, false, false, true, false, false];
        let mut shifted_item_bits = vec![false, true];
        shifted_item_bits.extend_from_slice(&[
            true, true, // position residuals if an external owner consumed the gap.
            false, true, false, true, true, // scalar orientation branch plus residuals.
            false, false, false, false, false, // item state bits.
            false, // direct CExoString item name.
        ]);

        let mut source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        source_bits.extend_from_slice(&add_source_bits);
        source_bits.extend_from_slice(&shifted_item_bits);
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend_from_slice(&add_emitted_bits);
        fragment_bits.extend_from_slice(&shifted_item_bits);

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        let item_bit_cursor = add_start_bit_cursor + add_emitted_bits.len();
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: item_offset,
                emitted_bit_start: add_start_bit_cursor,
                emitted_bit_end: item_bit_cursor,
                bits_inserted: 1,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let neighbor = nearest_unowned_item_update_neighbor_cursor(
            &live,
            item_offset,
            live.len(),
            &fragment_bits,
            item_bit_cursor,
            &ledger,
        )
        .expect("the scalar-shaped item row should validate only after a two-bit gap");

        assert_eq!(neighbor.delta, 2);
        assert_eq!(neighbor.emitted_gap_bits, 2);
        assert_eq!(neighbor.source_gap_bits, 2);
        assert_eq!(neighbor.previous_family, "item-create-rewrite");
        assert_eq!(
            neighbor.gap_origin,
            LiveObjectUpdateItemCursorGapOrigin::FocusPositionBits,
            "the +2 scalar neighbor starts only after the inherited cursor's item position bits"
        );
        let focus_prefix = neighbor
            .focus_prefix
            .expect("the shifted neighbor should retain the focus-row prefix it skipped");
        assert_eq!(focus_prefix.focus_bit_cursor, item_bit_cursor);
        assert_eq!(focus_prefix.candidate_bit_cursor, item_bit_cursor + 2);
        assert_eq!(focus_prefix.prefix_bits, 2);
        assert_eq!(focus_prefix.stages_retained, 1);
        let prefix_stage =
            focus_prefix.stages[0].expect("position prefix stage should be retained");
        assert_eq!(
            prefix_stage.stage,
            LiveObjectUpdateItemHandoffFocusPrefixStage::PositionResiduals
        );
        assert_eq!(prefix_stage.consumed_bits, 2);
        assert_eq!(
            prefix_stage.field_bits,
            LEGACY_UPDATE_POSITION_FRAGMENT_BITS
        );
        assert_ne!(
            neighbor.focus_failure_stage, "none",
            "the valid neighbor must retain the inherited-cursor parse failure"
        );
        assert_eq!(
            neighbor.focus_failure_orientation_vector,
            Some(true),
            "the real cursor selects the vector branch before the scalar-shaped neighbor fits"
        );
        assert!(neighbor.focus_failure_bit_cursor >= item_bit_cursor);
    }

    #[test]
    fn item_failure_source_window_neighbor_fit_reports_focus_row_start() {
        let mut live = Vec::new();
        live.extend_from_slice(&[b'D', ITEM_OBJECT_TYPE, 0x20, 0, 0, 0]);
        let item_offset = live.len();
        live.extend_from_slice(&diagnostic_full_item_update_live_bytes());

        let rows = live_object_source_window_rows(&live, item_offset, live.len(), 1, 0);
        let mut fragment_bits = vec![false, false, false, false];
        fragment_bits.extend_from_slice(&[
            false, true, // unowned residue before the item update.
            true, true, // item position residuals if a prior owner consumed the residue.
            false, true, false, true, true, // scalar-orientation selector plus residual bits.
            false, false, false, false, false, // item state bits.
            false, // direct CExoString item name.
        ]);
        let claims = live_object_source_window_row_bit_claims(
            &live,
            &rows,
            &fragment_bits,
            CNW_FRAGMENT_HEADER_BITS,
        );

        assert_eq!(claims.len(), 2);
        assert_eq!(claims[0].family, "delete");
        assert_eq!(claims[0].bit_end, Some(CNW_FRAGMENT_HEADER_BITS + 1));
        assert_eq!(claims[1].offset, item_offset);
        assert_eq!(claims[1].bit_start, CNW_FRAGMENT_HEADER_BITS + 1);
        assert_eq!(claims[1].bit_end, None);

        let neighbors = live_object_source_window_item_neighbor_cursor_claims(
            &live,
            &rows[1],
            &fragment_bits,
            claims[1].bit_start,
            claims[0].bit_end,
            &LiveObjectRewriteBitLedger::new(),
        );
        let plus_two = neighbors
            .iter()
            .find(|neighbor| neighbor.delta == 2)
            .expect("the active scalar-shaped item bytes should validate only at cursor +2");
        assert_eq!(plus_two.bit_start, claims[1].bit_start + 2);
        assert_eq!(plus_two.relation, "inside-focus-row");
        assert_eq!(
            plus_two.translated_mask,
            super::item::translate_update_mask(0xFFFF_FFF3)
        );
        assert_eq!(plus_two.orientation_vector, Some(false));
        assert_eq!(
            plus_two.source_owner,
            LiveObjectUpdateItemCursorSourceOwner::NoLedger
        );
        assert_eq!(
            plus_two.bit_end.saturating_sub(plus_two.bit_start),
            LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS
                + LEGACY_UPDATE_STATE_FRAGMENT_BITS
                + 1,
            "the nearby fit is a scalar item claim, not a prior-row owner"
        );
        assert_eq!(
            plus_two.read_end,
            live.len(),
            "the nearby item candidate consumes the bounded U/6 read bytes"
        );
    }

    #[test]
    fn item_neighbor_gap_origin_advances_through_orientation_branch_before_state() {
        let mask = LEGACY_UPDATE_POSITION_MASK
            | LEGACY_UPDATE_ORIENTATION_MASK
            | LEGACY_UPDATE_STATE_MASK
            | LEGACY_UPDATE_NAME_MASK;
        let focus = 20usize;
        let scalar_orientation_end = focus
            + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
            + 1
            + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS;
        let vector_orientation_end = focus
            + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
            + 1
            + EE_UPDATE_ORIENTATION_VECTOR_FRAGMENT_BITS;

        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusOrientationScalarPrefixBits,
            "a scalar branch fit at the orientation end is still orientation-owned"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusStatePrefixBits,
            "state attribution must start after the scalar orientation payload"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(false),
                focus,
                scalar_orientation_end + LEGACY_UPDATE_STATE_FRAGMENT_BITS + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusNameOrLocstringPrefixBits,
            "name attribution must start only after scalar orientation and state bits"
        );

        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(true),
                focus,
                vector_orientation_end
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusOrientationVectorPrefixBits,
            "a vector branch fit at the orientation end is still orientation-owned"
        );
        assert_eq!(
            live_object_item_update_focus_gap_origin(
                mask,
                Some(true),
                focus,
                vector_orientation_end + 1
            ),
            LiveObjectUpdateItemCursorGapOrigin::FocusStatePrefixBits,
            "state attribution must start after the vector orientation payload"
        );
    }

    #[test]
    fn rewrite_bit_ledger_tracks_source_and_emitted_cursors() {
        let mut live = vec![0; 32];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[6] = b'U';
        live[7] = DOOR_OBJECT_TYPE;
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 6,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 6,
                bits_inserted: 0,
                bits_removed: 0,
                family: "add-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 6,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 6,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 19,
                bits_inserted: 6,
                bits_removed: 1,
                family: "update-rewrite",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 16,
                record_end: 32,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 19,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 25,
                bits_inserted: 1,
                bits_removed: 0,
                family: "add-rewrite",
            },
        ));

        let entries = ledger.entries();
        assert_eq!(entries.len(), 3);
        assert_eq!(entries[0].source_bit_start, CNW_FRAGMENT_HEADER_BITS);
        assert_eq!(entries[0].source_bit_end, CNW_FRAGMENT_HEADER_BITS + 6);
        assert_eq!(entries[1].source_bit_start, CNW_FRAGMENT_HEADER_BITS + 6);
        assert_eq!(
            entries[1].source_bit_end,
            CNW_FRAGMENT_HEADER_BITS + 14,
            "six inserted EE bits and one removed legacy bit mean the source row consumed eight bits"
        );
        assert_eq!(entries[1].emitted_bit_end, CNW_FRAGMENT_HEADER_BITS + 19);
        assert_eq!(entries[2].source_bit_start, CNW_FRAGMENT_HEADER_BITS + 14);
        assert_eq!(entries[2].source_bit_end, CNW_FRAGMENT_HEADER_BITS + 19);
        assert_eq!(entries[2].emitted_bit_end, CNW_FRAGMENT_HEADER_BITS + 25);
        assert_eq!(
            ledger.source_bit_cursor(),
            CNW_FRAGMENT_HEADER_BITS + 19,
            "the source cursor remains distinct from the EE-emitted cursor after insertions"
        );
    }

    #[test]
    fn rewrite_bit_ledger_inserts_appearance_promoted_bits_before_following_update() {
        let mut live = vec![0; 32];
        live[0] = b'P';
        live[1] = CREATURE_OBJECT_TYPE;
        live[16] = b'U';
        live[17] = CREATURE_OBJECT_TYPE;

        let appearance_source_bits = [true];
        let appearance_emitted_bits = [true, false, false];
        let promoted_bits = [false, true];
        let following_update_tail_bits = [
            true, true, false, true, false, false, true, false, true, false,
        ];
        let mut source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        source_bits.extend_from_slice(&appearance_source_bits);
        source_bits.extend_from_slice(&following_update_tail_bits);
        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend_from_slice(&appearance_emitted_bits);
        fragment_bits.extend_from_slice(&promoted_bits);
        fragment_bits.extend_from_slice(&following_update_tail_bits);

        let appearance_start = CNW_FRAGMENT_HEADER_BITS;
        let appearance_end = appearance_start + appearance_emitted_bits.len();
        let update_end = appearance_end + promoted_bits.len() + following_update_tail_bits.len();
        let appearance_commit = LiveObjectRewriteBitLedgerCommit {
            offset: 0,
            record_end: 16,
            emitted_bit_start: appearance_start,
            emitted_bit_end: appearance_end,
            bits_inserted: appearance_emitted_bits.len() - appearance_source_bits.len(),
            bits_removed: 0,
            family: "creature-appearance-rewrite",
        };
        let update_commit = LiveObjectRewriteBitLedgerCommit {
            offset: 16,
            record_end: 32,
            emitted_bit_start: appearance_end,
            emitted_bit_end: update_end,
            bits_inserted: 0,
            bits_removed: 0,
            family: "creature-update-exact",
        };

        let mut missing_promoted = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(missing_promoted.commit_record(&live, appearance_commit));
        assert!(
            !missing_promoted.commit_record(&live, update_commit),
            "without the appearance-adjacent source insert, the following U/5 row over-claims the source snapshot"
        );

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(ledger.commit_record(&live, appearance_commit));
        assert!(ledger.insert_promoted_source_bits_from_fragment(
            &fragment_bits,
            appearance_end,
            promoted_bits.len(),
        ));
        assert!(ledger.commit_record(&live, update_commit));

        let entries = ledger.entries();
        assert_eq!(entries.len(), 2);
        assert_eq!(entries[0].family, "creature-appearance-rewrite");
        assert_eq!(entries[0].source_bit_end, appearance_start + 1);
        assert_eq!(entries[1].source_bit_start, appearance_start + 1);
        assert_eq!(
            entries[1].source_bit_end,
            source_bits.len() + promoted_bits.len()
        );
        assert_eq!(ledger.source_bit_cursor(), entries[1].source_bit_end);
    }

    #[test]
    fn rewrite_bit_ledger_rejects_source_span_past_snapshot() {
        let mut live = vec![0; 8];
        live[0] = b'A';
        live[1] = ITEM_OBJECT_TYPE;
        let source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS + 2];
        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);

        assert!(!ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 3,
                bits_inserted: 0,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));
        assert_eq!(
            ledger.source_bit_cursor(),
            CNW_FRAGMENT_HEADER_BITS,
            "an impossible source claim must not advance the ledger cursor"
        );
        assert!(ledger.entries().is_empty());

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 2,
                bits_inserted: 0,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));
        assert_eq!(ledger.source_bit_cursor(), source_bits.len());
    }

    #[test]
    fn source_window_initial_cursor_uses_ledger_anchor_for_midstream_rows() {
        let mut live = vec![0; 40];
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        live[28] = b'U';
        live[29] = ITEM_OBJECT_TYPE;
        let first_row = LiveObjectSourceWindowRow {
            offset: 16,
            record_end: 28,
            opcode: b'A',
            marker: ITEM_OBJECT_TYPE,
            object_id: None,
            update_mask: None,
        };
        let focus_row = LiveObjectSourceWindowRow {
            offset: 28,
            record_end: 40,
            opcode: b'U',
            marker: ITEM_OBJECT_TYPE,
            object_id: None,
            update_mask: None,
        };
        let rows = [first_row, focus_row];
        let source_bits = vec![false; CNW_FRAGMENT_HEADER_BITS + 16];
        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: first_row.offset,
                record_end: first_row.record_end,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 14,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 20,
                bits_inserted: 1,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        assert_eq!(
            live_object_source_window_initial_bit_cursor(
                &rows,
                CNW_FRAGMENT_HEADER_BITS + 25,
                &ledger,
            ),
            CNW_FRAGMENT_HEADER_BITS + 14,
            "mid-stream source windows should replay from the ledgered row cursor, not the failed focus cursor"
        );

        let empty_ledger = LiveObjectRewriteBitLedger::new();
        assert_eq!(
            live_object_source_window_initial_bit_cursor(
                &rows,
                CNW_FRAGMENT_HEADER_BITS + 25,
                &empty_ledger,
            ),
            CNW_FRAGMENT_HEADER_BITS + 25,
            "without a ledger anchor, a mid-stream diagnostic must keep the focus cursor fallback"
        );

        let mut rows_from_start = rows;
        rows_from_start[0].offset = 0;
        assert_eq!(
            live_object_source_window_initial_bit_cursor(
                &rows_from_start,
                CNW_FRAGMENT_HEADER_BITS + 25,
                &empty_ledger,
            ),
            CNW_FRAGMENT_HEADER_BITS,
            "windows beginning at the live-object stream start still use the CNW payload cursor"
        );
    }

    #[test]
    fn rewrite_bit_ledger_classifies_unowned_emitted_cursor_gap() {
        let mut live = vec![0; 32];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[6] = b'U';
        live[7] = DOOR_OBJECT_TYPE;
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 6,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 6,
                bits_inserted: 0,
                bits_removed: 0,
                family: "add-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 6,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 6,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 19,
                bits_inserted: 6,
                bits_removed: 1,
                family: "update-rewrite",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 16,
                record_end: 32,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 19,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 25,
                bits_inserted: 1,
                bits_removed: 0,
                family: "add-rewrite",
            },
        ));

        let exact_cursor = ledger
            .gap_before_cursor(CNW_FRAGMENT_HEADER_BITS + 25)
            .expect("exact cursor should be classified against the previous row");
        assert_eq!(exact_cursor.relation, "after-previous-emitted-end");
        assert_eq!(exact_cursor.emitted_gap_bits, 0);
        assert_eq!(
            (
                exact_cursor.emitted_gap_bit_start,
                exact_cursor.emitted_gap_bit_end
            ),
            (CNW_FRAGMENT_HEADER_BITS + 25, CNW_FRAGMENT_HEADER_BITS + 25)
        );
        assert_eq!(exact_cursor.source_relation, "after-previous-source-end");
        assert_eq!(exact_cursor.source_gap_bits, 0);
        assert_eq!(
            (
                exact_cursor.source_gap_bit_start,
                exact_cursor.source_gap_bit_end
            ),
            (CNW_FRAGMENT_HEADER_BITS + 19, CNW_FRAGMENT_HEADER_BITS + 19)
        );
        assert_eq!(
            exact_cursor.previous_source_bit_start,
            CNW_FRAGMENT_HEADER_BITS + 14
        );
        assert_eq!(
            exact_cursor.previous_source_bit_end,
            CNW_FRAGMENT_HEADER_BITS + 19
        );
        assert_eq!(
            exact_cursor.previous_emitted_bit_start,
            CNW_FRAGMENT_HEADER_BITS + 19
        );
        assert_eq!(
            exact_cursor.previous_emitted_bit_end,
            CNW_FRAGMENT_HEADER_BITS + 25
        );
        assert_eq!(exact_cursor.cumulative_emitted_source_delta, 6);
        assert_eq!(
            exact_cursor.implied_source_cursor,
            CNW_FRAGMENT_HEADER_BITS + 19,
            "the exact emitted handoff maps back to the source end after removing EE insertions"
        );
        assert_eq!(
            exact_cursor.source_emitted_delta_after_previous, 6,
            "the focus cursor is six EE-inserted bits beyond the source cursor"
        );

        let shifted_candidate = ledger
            .gap_before_cursor(CNW_FRAGMENT_HEADER_BITS + 27)
            .expect("shifted neighbor cursor should be classified against the previous row");
        assert_eq!(shifted_candidate.relation, "unowned-emitted-gap");
        assert_eq!(shifted_candidate.emitted_gap_bits, 2);
        assert_eq!(
            (
                shifted_candidate.emitted_gap_bit_start,
                shifted_candidate.emitted_gap_bit_end
            ),
            (CNW_FRAGMENT_HEADER_BITS + 25, CNW_FRAGMENT_HEADER_BITS + 27)
        );
        assert_eq!(shifted_candidate.source_relation, "unowned-source-gap");
        assert_eq!(shifted_candidate.source_gap_bits, 2);
        assert_eq!(
            (
                shifted_candidate.source_gap_bit_start,
                shifted_candidate.source_gap_bit_end
            ),
            (CNW_FRAGMENT_HEADER_BITS + 19, CNW_FRAGMENT_HEADER_BITS + 21)
        );
        assert_eq!(shifted_candidate.cumulative_emitted_source_delta, 6);
        assert_eq!(
            shifted_candidate.implied_source_cursor,
            CNW_FRAGMENT_HEADER_BITS + 21,
            "subtracting the committed EE insertion delta still leaves a two-bit source gap"
        );
        assert_eq!(
            shifted_candidate.source_emitted_delta_after_previous, 8,
            "a +2 neighboring fit requires two unowned emitted bits after the committed rows"
        );

        let tail = ledger
            .contiguous_tail_before_cursor(CNW_FRAGMENT_HEADER_BITS + 27)
            .expect("shifted cursor should retain the contiguous committed handoff");
        assert_eq!(tail.entry_count, 3);
        assert_eq!(
            ledger.contiguous_tail_family_chain(tail),
            "add-exact->update-rewrite->add-rewrite"
        );
        assert_eq!(
            ledger.contiguous_tail_row_chain(tail),
            "0..6:add-exact[src=3..9,emit=3..9,+0,-0]->6..16:update-rewrite[src=9..17,emit=9..22,+6,-1]->16..32:add-rewrite[src=17..22,emit=22..28,+1,-0]",
            "the diagnostic chain must preserve per-row source/emitted spans"
        );
        assert_eq!(
            format_rewrite_bit_ledger_contiguous_tail(&ledger, CNW_FRAGMENT_HEADER_BITS + 27),
            "entries=3 families=add-exact->update-rewrite->add-rewrite rows=0..6:add-exact[src=3..9,emit=3..9,+0,-0]->6..16:update-rewrite[src=9..17,emit=9..22,+6,-1]->16..32:add-rewrite[src=17..22,emit=22..28,+1,-0] source=3..22 emitted=3..28 emitted_gap_to_cursor=2 source_gap_to_cursor=2",
            "single-line failure diagnostics need the same row-level provenance"
        );
        assert_eq!(
            (tail.source_bit_start, tail.source_bit_end),
            (CNW_FRAGMENT_HEADER_BITS, CNW_FRAGMENT_HEADER_BITS + 19)
        );
        assert_eq!(
            (tail.emitted_bit_start, tail.emitted_bit_end),
            (CNW_FRAGMENT_HEADER_BITS, CNW_FRAGMENT_HEADER_BITS + 25)
        );
        assert_eq!(
            (tail.emitted_gap_to_cursor, tail.source_gap_to_cursor),
            (2, 2),
            "the contiguous row chain still leaves the same two-bit source/emitted gap"
        );
    }

    #[test]
    fn rewrite_bit_ledger_source_gap_values_use_source_snapshot() {
        let mut live = vec![0; 16];
        live[0] = b'A';
        live[1] = ITEM_OBJECT_TYPE;
        let source_bits = vec![
            false, false, false, // CNW header
            true, false, true, true, // first row source bits
            true, false, // unowned source gap bits
        ];
        let mut rewritten_bits = source_bits.clone();
        rewritten_bits.splice(5..5, [false, false, false]);

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 7,
                bits_inserted: 3,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let gap = ledger
            .gap_before_cursor(CNW_FRAGMENT_HEADER_BITS + 9)
            .expect("shifted cursor should expose a two-bit source gap");
        assert_eq!(
            ledger.source_gap_values(&rewritten_bits, &gap),
            &[true, false],
            "source gap diagnostics must use the pre-rewrite source bit coordinates"
        );
        assert_eq!(
            rewritten_bits
                .get(gap.source_gap_bit_start..gap.source_gap_bit_end)
                .unwrap_or(&[]),
            &[false, true],
            "a stale post-rewrite slice at source coordinates would report the wrong bits"
        );
        assert_eq!(
            ledger.emitted_gap_values(&rewritten_bits, &gap),
            &[true, false],
            "emitted gap diagnostics still describe the current EE-facing bitstream"
        );
    }

    #[test]
    fn rewrite_bit_ledger_entry_values_use_source_snapshot() {
        let mut live = vec![0; 16];
        live[0] = b'A';
        live[1] = ITEM_OBJECT_TYPE;
        let source_bits = vec![
            false, false, false, // CNW header
            true, false, true, true, // item-create source bits
            true, false, // following unowned source bits
        ];
        let mut rewritten_bits = source_bits.clone();
        rewritten_bits.splice(5..5, [false, false, false]);

        let mut ledger = LiveObjectRewriteBitLedger::with_source_bits(&source_bits);
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: live.len(),
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 7,
                bits_inserted: 3,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let entry = ledger.entries().last().expect("ledger row should exist");
        assert_eq!(
            ledger.source_values_for_entry(&rewritten_bits, entry),
            &[true, false, true, true],
            "row source diagnostics must use immutable source coordinates"
        );
        assert_eq!(
            rewritten_bits
                .get(entry.source_bit_start..entry.source_bit_end)
                .unwrap_or(&[]),
            &[true, false, false, false],
            "reading source spans from the rewritten bitstream would report EE insertion bits"
        );
        assert_eq!(
            ledger.emitted_values_for_entry(&rewritten_bits, entry),
            &[true, false, false, false, false, true, true],
            "row emitted diagnostics still describe the current EE-facing bitstream"
        );
    }

    #[test]
    fn rewrite_bit_ledger_contiguous_tail_stops_at_emitted_gap() {
        let mut live = vec![0; 24];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[8] = b'G';
        live[9] = b'Q';
        live[16] = b'A';
        live[17] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 8,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 4,
                bits_inserted: 0,
                bits_removed: 0,
                family: "add-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 8,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 7,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 9,
                bits_inserted: 0,
                bits_removed: 0,
                family: "live-gui-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 16,
                record_end: 24,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 9,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 15,
                bits_inserted: 1,
                bits_removed: 0,
                family: "item-create-rewrite",
            },
        ));

        let tail = ledger
            .contiguous_tail_before_cursor(CNW_FRAGMENT_HEADER_BITS + 17)
            .expect("tail should classify against the latest contiguous run");

        assert_eq!(tail.entry_count, 2);
        assert_eq!(
            ledger.contiguous_tail_family_chain(tail),
            "live-gui-exact->item-create-rewrite",
            "the earlier add row is separated by an emitted cursor gap"
        );
        assert_eq!(
            (tail.emitted_bit_start, tail.emitted_bit_end),
            (CNW_FRAGMENT_HEADER_BITS + 7, CNW_FRAGMENT_HEADER_BITS + 15)
        );
        assert_eq!(
            (tail.source_bit_start, tail.source_bit_end),
            (CNW_FRAGMENT_HEADER_BITS + 4, CNW_FRAGMENT_HEADER_BITS + 11)
        );
        assert_eq!(
            (tail.emitted_gap_to_cursor, tail.source_gap_to_cursor),
            (2, 2),
            "the latest contiguous run cannot explain a later two-bit cursor shift"
        );
    }

    #[test]
    fn rewrite_bit_ledger_keeps_delete_rows_as_cursor_owners() {
        let mut live = vec![0; 32];
        live[0] = b'A';
        live[1] = DOOR_OBJECT_TYPE;
        live[6] = b'D';
        live[7] = ITEM_OBJECT_TYPE;
        live[16] = b'U';
        live[17] = ITEM_OBJECT_TYPE;
        let mut ledger = LiveObjectRewriteBitLedger::new();

        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 0,
                record_end: 6,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 6,
                bits_inserted: 0,
                bits_removed: 0,
                family: "add-exact",
            },
        ));
        assert!(ledger.commit_record(
            &live,
            LiveObjectRewriteBitLedgerCommit {
                offset: 6,
                record_end: 16,
                emitted_bit_start: CNW_FRAGMENT_HEADER_BITS + 6,
                emitted_bit_end: CNW_FRAGMENT_HEADER_BITS + 7,
                bits_inserted: 0,
                bits_removed: 0,
                family: "delete-exact",
            },
        ));

        let exact_cursor = ledger
            .gap_before_cursor(CNW_FRAGMENT_HEADER_BITS + 7)
            .expect("cursor after delete row should be classified");
        assert_eq!(exact_cursor.previous_family, "delete-exact");
        assert_eq!(exact_cursor.previous_offset, 6);
        assert_eq!(exact_cursor.relation, "after-previous-emitted-end");
        assert_eq!(exact_cursor.source_relation, "after-previous-source-end");
        assert_eq!(
            exact_cursor.source_gap_bits, 0,
            "a following row at the exact cursor starts after the proven delete bit"
        );

        let shifted_candidate = ledger
            .gap_before_cursor(CNW_FRAGMENT_HEADER_BITS + 9)
            .expect("shifted cursor after delete row should be classified");
        assert_eq!(shifted_candidate.previous_family, "delete-exact");
        assert_eq!(shifted_candidate.emitted_gap_bits, 2);
        assert_eq!(shifted_candidate.source_gap_bits, 2);
        assert_eq!(
            shifted_candidate.source_relation, "unowned-source-gap",
            "a neighboring fit after a delete row still needs a separate source owner"
        );
    }

