    #[test]
    fn exact_placeable_update_reconciles_unique_area_static_position() {
        let object_id = 0x8000_34D8u32;
        let mask =
            LEGACY_UPDATE_POSITION_MASK | LEGACY_UPDATE_ORIENTATION_MASK | LEGACY_UPDATE_STATE_MASK;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&mask.to_le_bytes());
        live.extend_from_slice(&[0x10, 0x00, 0x20, 0x00, 0x30, 0x00]);
        live.push(0x70);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, true, // position Z residual bits.
            false, true, false, true, false, // scalar orientation 0x70A.
            false, true, false, true, false, // lockable=true, locked=false.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact U/09 payload");
        let claim = claim_payload_if_verified(&payload).expect("pre-rewrite exact U/09");
        let source_position = claim.mentions[0]
            .position
            .expect("pre-rewrite exact U/09 should expose position");
        assert!((source_position.x - 0.16).abs() < 0.0001);
        assert!((source_position.y - 0.32).abs() < 0.0001);
        assert!(
            source_position.z > -20.0 && source_position.z < -19.0,
            "source Z should decode from the 16 read-buffer bits plus two residual bits"
        );

        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                x: 12.34,
                y: 56.78,
                z: 0.0,
                has_direction: false,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    lockable: true,
                    locked: false,
                    ..crate::translate::area::AreaPlaceableContextState::default()
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("unique static context should reconcile exact U/09 position");
        assert_eq!(summary.add_records_examined, 0);
        assert_eq!(summary.update_records_examined, 1);
        assert_eq!(summary.add_records_rewritten, 0);
        assert_eq!(summary.update_records_rewritten, 1);
        assert_eq!(summary.exact_placeable_add_appearance_rewritten, 0);
        assert_eq!(summary.exact_placeable_add_state_rewritten, 0);
        assert_eq!(summary.exact_placeable_update_position_rewritten, 1);
        assert_eq!(summary.exact_placeable_update_appearance_rewritten, 0);
        assert_eq!(summary.exact_placeable_update_orientation_rewritten, 0);
        assert_eq!(summary.exact_placeable_update_state_rewritten, 0);
        assert_eq!(summary.bits_inserted, 0);
        assert_eq!(summary.bits_removed, 0);
        assert_eq!(summary.old_live_bytes_length, summary.new_live_bytes_length);

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite exact U/09 claim");
        let position = claim.mentions[0]
            .position
            .expect("post-rewrite exact U/09 should retain position mention");
        assert!((position.x - 12.34).abs() < 0.0001);
        assert!((position.y - 56.78).abs() < 0.0001);
        assert!((position.z - 0.0).abs() < 0.001);
        assert_eq!(
            claim.mentions[0].orientation,
            Some(LiveObjectRecordOrientation {
                source: LiveObjectRecordOrientationSource::Scalar,
                scalar_tenths_degrees: 0x70A,
                vector: None,
            }),
            "position reconciliation must not disturb the parser-owned orientation bits"
        );
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                lockable: Some(true),
                locked: Some(false),
                ..LiveObjectPlaceableState::default()
            }),
            "position reconciliation must not disturb the parser-owned state block"
        );

        let rewritten_live = &payload[HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES..claim.declared];
        assert_eq!(
            read_u16_le(rewritten_live, LEGACY_UPDATE_HEADER_BYTES),
            Some(1234)
        );
        assert_eq!(
            read_u16_le(rewritten_live, LEGACY_UPDATE_HEADER_BYTES + 2),
            Some(5678)
        );
        let target_z_raw = encode_ee_position_z(0.0).expect("test Z should be encodable");
        assert_eq!(
            read_u16_le(rewritten_live, LEGACY_UPDATE_HEADER_BYTES + 4),
            Some((target_z_raw >> 2) as u16)
        );
        let rewritten_bits =
            bits::decode_msb_valid_bits(&payload[claim.declared..], CNW_FRAGMENT_HEADER_BITS)
                .expect("rewritten exact U/09 fragment bits");
        assert_eq!(
            &rewritten_bits[CNW_FRAGMENT_HEADER_BITS
                ..CNW_FRAGMENT_HEADER_BITS + LEGACY_UPDATE_POSITION_FRAGMENT_BITS],
            &[((target_z_raw >> 1) & 1) != 0, (target_z_raw & 1) != 0],
            "Z residual bits must stay at the parser-owned position cursor"
        );
        assert_eq!(
            &rewritten_bits[CNW_FRAGMENT_HEADER_BITS + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                ..CNW_FRAGMENT_HEADER_BITS
                    + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                    + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS],
            &[false, true, false, true, false],
            "the following scalar orientation bits must be unchanged"
        );
    }

    #[test]
    fn exact_placeable_update_reconciles_visual_fields_from_one_verified_claim() {
        let object_id = 0x8000_34D8u32;
        let mask = LEGACY_UPDATE_POSITION_MASK
            | LEGACY_UPDATE_ORIENTATION_MASK
            | LEGACY_UPDATE_APPEARANCE_MASK
            | LEGACY_UPDATE_STATE_MASK;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&mask.to_le_bytes());
        live.extend_from_slice(&[0x10, 0x00, 0x20, 0x00, 0x30, 0x00]);
        live.push(0x70);
        live.extend_from_slice(&0x0011u16.to_le_bytes());

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, true, // position fragment bits.
            false, true, false, true, false, // scalar orientation 0x70A.
            false, true, false, true, false, // lockable=true, locked=false.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact U/09 payload");

        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0x0022,
                dir_x: -1.0,
                dir_y: 0.0,
                dir_z: 0.0,
                has_direction: true,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    lockable: false,
                    locked: true,
                    ..crate::translate::area::AreaPlaceableContextState::default()
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("unique static context should reconcile exact U/09 visual fields");
        assert_eq!(summary.add_records_examined, 0);
        assert_eq!(summary.update_records_examined, 1);
        assert_eq!(summary.add_records_rewritten, 0);
        assert_eq!(summary.update_records_rewritten, 1);
        assert_eq!(summary.bits_inserted, 0);
        assert_eq!(summary.bits_removed, 0);
        assert_eq!(summary.old_live_bytes_length, summary.new_live_bytes_length);

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite exact U/09 claim");
        assert_eq!(claim.mentions.len(), 1);
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0022,
                resref: None,
            })
        );
        assert_eq!(
            claim.mentions[0].orientation,
            Some(LiveObjectRecordOrientation {
                source: LiveObjectRecordOrientationSource::Scalar,
                scalar_tenths_degrees: 900,
                vector: None,
            })
        );
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                lockable: Some(false),
                locked: Some(true),
                ..LiveObjectPlaceableState::default()
            }),
            "appearance, orientation, and state are all reconciled through the same exact U/09 parser claim"
        );

        let rewritten_live = &payload[HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES..claim.declared];
        assert_eq!(
            read_u16_le(
                rewritten_live,
                LEGACY_UPDATE_HEADER_BYTES
                    + LEGACY_UPDATE_POSITION_READ_BYTES
                    + EE_UPDATE_ORIENTATION_SCALAR_READ_BYTES,
            ),
            Some(0x0022),
            "the parser-owned appearance word is rewritten in place"
        );
        let rewritten_bits =
            bits::decode_msb_valid_bits(&payload[claim.declared..], CNW_FRAGMENT_HEADER_BITS)
                .expect("rewritten exact U/09 fragment bits");
        assert_eq!(
            &rewritten_bits[CNW_FRAGMENT_HEADER_BITS + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                ..CNW_FRAGMENT_HEADER_BITS
                    + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                    + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS],
            &[false, false, true, false, false],
            "the scalar selector plus four low bits should encode 0x384"
        );
        assert_eq!(
            &rewritten_bits[CNW_FRAGMENT_HEADER_BITS
                + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS
                ..CNW_FRAGMENT_HEADER_BITS
                    + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                    + EE_UPDATE_ORIENTATION_SCALAR_FRAGMENT_BITS
                    + LEGACY_UPDATE_STATE_FRAGMENT_BITS],
            &[false, true, true, false, false],
            "the parser-owned placeable state block keeps its exact five-bit width"
        );
    }

    #[test]
    fn exact_placeable_update_reconciles_unique_area_static_vector_orientation() {
        let object_id = 0x8000_34D8u32;
        let mask =
            LEGACY_UPDATE_POSITION_MASK | LEGACY_UPDATE_ORIENTATION_MASK | LEGACY_UPDATE_STATE_MASK;
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&mask.to_le_bytes());
        live.extend_from_slice(&[0x10, 0x00, 0x20, 0x00, 0x30, 0x00]);
        live.extend_from_slice(&[0x01, 0x00, 0x02, 0x00, 0x03, 0x00]);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, true, // position fragment bits.
            true, // vector-orientation selector; no scalar low bits follow.
            false, true, false, true, false, // lockable=true, locked=false.
        ]);
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact vector U/09");
        let claim = claim_payload_if_verified(&payload).expect("pre-rewrite exact vector U/09");
        let orientation = claim.mentions[0]
            .orientation
            .expect("exact vector U/09 should expose orientation diagnostics");
        assert_eq!(
            orientation.source,
            LiveObjectRecordOrientationSource::Vector
        );
        assert_eq!(orientation.scalar_tenths_degrees, 1350);
        let vector = orientation
            .vector
            .expect("vector orientation should retain parser-owned components");
        assert!(
            vector.x < -1.99 && vector.y < -1.99 && vector.z < -1.99,
            "raw vector WORDs should remain visible before reconciliation: {vector:?}"
        );

        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                dir_x: -1.0,
                dir_y: 0.0,
                dir_z: 0.0,
                has_direction: true,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    lockable: true,
                    locked: false,
                    ..crate::translate::area::AreaPlaceableContextState::default()
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("unique static context should reconcile exact vector U/09 orientation");
        assert_eq!(summary.add_records_examined, 0);
        assert_eq!(summary.update_records_examined, 1);
        assert_eq!(summary.add_records_rewritten, 0);
        assert_eq!(summary.update_records_rewritten, 1);
        assert_eq!(summary.bits_inserted, 0);
        assert_eq!(summary.bits_removed, 0);
        assert_eq!(summary.old_live_bytes_length, summary.new_live_bytes_length);

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite exact vector U/09");
        let orientation = claim.mentions[0]
            .orientation
            .expect("post-rewrite exact vector U/09 orientation");
        assert_eq!(
            orientation.source,
            LiveObjectRecordOrientationSource::Vector,
            "reconciliation keeps the parser-owned vector branch instead of moving the cursor to scalar"
        );
        assert_eq!(orientation.scalar_tenths_degrees, 900);
        let vector = orientation
            .vector
            .expect("rewritten vector orientation should retain components");
        assert!(
            (vector.x + 1.0).abs() < 1.0e-4 && vector.y.abs() < 1.0e-4 && vector.z.abs() < 1.0e-4,
            "static direction bearing pi/2 should emit a normalized vector: {vector:?}"
        );
        assert_eq!(
            claim.mentions[0].placeable_state,
            Some(LiveObjectPlaceableState {
                lockable: Some(true),
                locked: Some(false),
                ..LiveObjectPlaceableState::default()
            }),
            "vector reconciliation must not disturb the parser-owned state block"
        );

        let rewritten_live = &payload[HIGH_LEVEL_HEADER_BYTES + CNW_LENGTH_BYTES..claim.declared];
        let vector_offset = LEGACY_UPDATE_HEADER_BYTES + LEGACY_UPDATE_POSITION_READ_BYTES;
        assert_eq!(
            read_u16_le(rewritten_live, vector_offset),
            writer::encode_ee_vector_orientation_component(-1.0)
        );
        assert_eq!(
            read_u16_le(rewritten_live, vector_offset + 2),
            writer::encode_ee_vector_orientation_component(0.0)
        );
        assert_eq!(
            read_u16_le(rewritten_live, vector_offset + 4),
            writer::encode_ee_vector_orientation_component(0.0)
        );
        let rewritten_bits =
            bits::decode_msb_valid_bits(&payload[claim.declared..], CNW_FRAGMENT_HEADER_BITS)
                .expect("rewritten exact vector U/09 fragment bits");
        assert!(
            rewritten_bits[CNW_FRAGMENT_HEADER_BITS + LEGACY_UPDATE_POSITION_FRAGMENT_BITS],
            "the vector selector bit remains true"
        );
        assert_eq!(
            &rewritten_bits[CNW_FRAGMENT_HEADER_BITS
                + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                + EE_UPDATE_ORIENTATION_VECTOR_FRAGMENT_BITS
                ..CNW_FRAGMENT_HEADER_BITS
                    + LEGACY_UPDATE_POSITION_FRAGMENT_BITS
                    + EE_UPDATE_ORIENTATION_VECTOR_FRAGMENT_BITS
                    + LEGACY_UPDATE_STATE_FRAGMENT_BITS],
            &[false, true, false, true, false],
            "the placeable state block keeps its exact five-bit width"
        );
    }

    #[test]
    fn exact_placeable_update_rewrites_resref_appearance_to_unique_area_static_word() {
        let object_id = 0x8000_34D8u32;
        let resref = *b"plc_visual_test\0";
        let mut live = vec![b'U', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&resref);
        let fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        let mut payload =
            live_object_payload_from_parts(&live, &fragment_bits).expect("exact resref U/09");
        let original = payload.clone();

        let area_context = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0x0022,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::Unique,
                module_state: Some(crate::translate::area::AreaPlaceableContextState {
                    static_object: true,
                    ..crate::translate::area::AreaPlaceableContextState::default()
                }),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("unique static context should collapse exact U/09 resref appearance");
        assert_eq!(summary.update_records_examined, 1);
        assert_eq!(summary.update_records_rewritten, 1);
        assert_eq!(summary.exact_placeable_update_unique_targets, 1);
        assert_eq!(summary.exact_placeable_appearance_custom_skipped, 0);
        assert_eq!(
            summary.exact_placeable_update_module_custom_appearance_skipped,
            0
        );
        assert_eq!(
            summary.exact_placeable_update_source_custom_appearance_rewritten,
            1
        );
        assert_eq!(summary.exact_placeable_update_appearance_rewritten, 1);
        assert_eq!(
            summary.bytes_removed,
            EE_UPDATE_APPEARANCE_RESREF_READ_BYTES as u32
        );
        assert_eq!(
            summary.old_live_bytes_length - summary.new_live_bytes_length,
            EE_UPDATE_APPEARANCE_RESREF_READ_BYTES
        );
        assert_eq!(
            summary.old_declared - summary.new_declared,
            EE_UPDATE_APPEARANCE_RESREF_READ_BYTES as u32
        );

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite exact U/09 claim");
        assert_eq!(
            claim.mentions[0].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0x0022,
                resref: None,
            }),
            "the parser-owned CResRef branch should be removed after the WORD becomes non-custom"
        );
        assert_eq!(
            payload.len() + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES,
            original.len()
        );
    }

