    #[test]
    fn exact_placeable_unproven_carrier_source_blocked_field_correlation_splits_outcomes() {
        let conflict = crate::translate::area::AreaPlaceableContextIdentityConflict {
            light_rows: 0,
            static_rows: 2,
            module_backed_static_rows: 1,
            module_unbacked_static_rows: 0,
            unproven_static_rows: 1,
            source_incompatible_static_rows: 1,
            source_read_mismatch_static_rows: 1,
            source_fragment_owned_static_rows: 1,
            source_read_mismatch_and_fragment_owned_static_rows: 1,
            area_alias_rows: 0,
            duplicate_object_id_rows: 1,
        };

        let mut summary = LiveObjectUpdateRewriteSummary::default();
        let unblocked_row = crate::translate::area::AreaPlaceableContextRow::default();
        let source_blocked_target =
            AreaPlaceableContextStaticReconciliationTarget::IdentityBlocked(conflict);
        let source_unblocked_target =
            AreaPlaceableContextStaticReconciliationTarget::UniqueModuleBacked(&unblocked_row);
        let add_only_carrier = ExactPlaceableUpdateAppearanceCarrier::default();

        for (base_target, field_rewritten) in [
            (source_blocked_target, true),
            (source_blocked_target, false),
            (source_unblocked_target, false),
        ] {
            ExactPlaceableUnprovenCustomCarrierRowEvidence::from_update_carrier_target_and_field_outcome(
                add_only_carrier,
                base_target,
                field_rewritten,
            )
            .record(&mut summary);
        }

        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_field_rewrite_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_field_unchanged_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_read_mismatch_field_rewrite_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_read_mismatch_field_unchanged_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_fragment_owned_field_rewrite_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_fragment_owned_field_unchanged_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_read_mismatch_and_fragment_owned_field_rewrite_targets,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_read_mismatch_and_fragment_owned_field_unchanged_targets,
            1
        );
        let disposition = summary.exact_placeable_unproven_custom_carrier_disposition();
        assert_eq!(disposition.skipped, 3);
        assert_eq!(disposition.source_blocked, 2);
        assert_eq!(disposition.source_blocked_field_rewrite_targets, 1);
        assert_eq!(disposition.source_blocked_field_unchanged_targets, 1);
        assert_eq!(disposition.source_blocked_field_unclassified_targets, 0);
        assert_eq!(
            disposition.source_owned_without_field_rewrite, 1,
            "source-blocked skips with unchanged add fields classify as P/04 ownership evidence"
        );
        assert_eq!(
            disposition.writer_gap_candidates, 2,
            "non-source-blocked skips plus source-blocked field rewrites remain writer-gap candidates"
        );
        assert_eq!(disposition.source_blocked_writer_gap_candidates, 1);
        assert_eq!(disposition.source_unblocked_writer_gap_candidates, 1);
        let slot_disposition = summary.exact_placeable_unproven_custom_carrier_slot_disposition();
        assert_eq!(slot_disposition.skipped.add_only, 3);
        assert_eq!(slot_disposition.writer_gap.add_only, 2);
        assert_eq!(slot_disposition.source_blocked_field_rewrite.add_only, 1);
        assert_eq!(slot_disposition.source_unblocked.add_only, 1);
        assert_eq!(
            slot_disposition.source_owned_without_field_rewrite.add_only,
            1
        );
    }

