    #[test]
    fn exact_placeable_pre_add_carrier_committed_origins_split_rewrite_target_state() {
        let add_resref = *b"plc_add_target\0\0";
        let other_resref = *b"plc_other_tgt\0\0\0";
        let add_row = crate::translate::area::AreaPlaceableContextRow {
            appearance: 0xFFFE,
            module_template_resref: Some(add_resref),
            ..crate::translate::area::AreaPlaceableContextRow::default()
        };
        let add_target = PlaceableUpdateAppearanceOutput {
            appearance: 0xFFFE,
            resref: Some(add_resref),
        };
        let other_target = PlaceableUpdateAppearanceOutput {
            appearance: 0xFFFE,
            resref: Some(other_resref),
        };
        let base_record = ExactPlaceableUpdateAppearanceCarrierRecord {
            record_offset: 8,
            record_end: 20,
            appearance_offset: 18,
            resref_offset: None,
            source_appearance: 0x0011,
            source_resref: None,
            fragment_bit_start: CNW_FRAGMENT_HEADER_BITS,
            fragment_bit_end: CNW_FRAGMENT_HEADER_BITS,
            position_output_equivalence: true,
            custom_rewrite_target_resolution:
                ExactPlaceableCustomCarrierRewriteTargetResolution::available(add_target),
        };

        let cases = [
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_normal: Some(base_record),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddNormalMatchingTarget,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddNormalMatchingTarget,
            ),
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_normal: Some(ExactPlaceableUpdateAppearanceCarrierRecord {
                        custom_rewrite_target_resolution:
                            ExactPlaceableCustomCarrierRewriteTargetResolution::available(
                                other_target,
                            ),
                        ..base_record
                    }),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddNormalRewriteTargetMismatch,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddNormalRewriteTargetMismatch,
            ),
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_normal: Some(ExactPlaceableUpdateAppearanceCarrierRecord {
                        custom_rewrite_target_resolution:
                            ExactPlaceableCustomCarrierRewriteTargetResolution::unavailable(
                            ExactPlaceableCustomCarrierRewriteTargetUnavailableReason::PositionOutputUnavailable,
                        ),
                        ..base_record
                    }),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddNormalTargetUnavailable,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddNormalTargetUnavailable,
            ),
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_custom: Some(ExactPlaceableUpdateAppearanceCarrierRecord {
                        resref_offset: Some(20),
                        source_appearance: 0xFFFE,
                        source_resref: Some(add_resref),
                        ..base_record
                    }),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddCustomMatchingTarget,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddCustomMatchingTarget,
            ),
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_custom: Some(ExactPlaceableUpdateAppearanceCarrierRecord {
                        resref_offset: Some(20),
                        source_appearance: 0xFFFE,
                        source_resref: Some(add_resref),
                        custom_rewrite_target_resolution:
                            ExactPlaceableCustomCarrierRewriteTargetResolution::available(
                                other_target,
                            ),
                        ..base_record
                    }),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddCustomRewriteTargetMismatch,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddCustomRewriteTargetMismatch,
            ),
            (
                ExactPlaceableUpdateAppearanceCarrier {
                    pre_add_custom: Some(ExactPlaceableUpdateAppearanceCarrierRecord {
                        resref_offset: Some(20),
                        source_appearance: 0xFFFE,
                        source_resref: Some(other_resref),
                        custom_rewrite_target_resolution:
                            ExactPlaceableCustomCarrierRewriteTargetResolution::unavailable(
                            ExactPlaceableCustomCarrierRewriteTargetUnavailableReason::PositionOutputUnavailable,
                        ),
                        ..base_record
                    }),
                    ..ExactPlaceableUpdateAppearanceCarrier::default()
                },
                ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddPreAddCustomTargetUnavailable,
                PlaceableCustomAppearanceUpdateInsertionOrigin::AfterAddPreAddCustomTargetUnavailable,
            ),
        ];

        let mut summary = LiveObjectUpdateRewriteSummary::default();
        for (carrier, expected_policy, expected_origin) in cases {
            assert_eq!(carrier.synthesis_policy(&add_row), expected_policy);
            let Some(ExactPlaceableCustomCarrierSynthesisInsertion::AfterAdd {
                origin,
                unavailable_reason,
                insertion_carrier,
            }) = carrier.synthesis_insertion(&add_row)
            else {
                panic!("expected add-boundary carrier synthesis insertion");
            };
            assert_eq!(origin, expected_origin);
            assert!(
                insertion_carrier.is_some(),
                "all policy cases in this table are selected-carrier syntheses"
            );
            count_committed_placeable_custom_appearance_update_origin(
                &mut summary,
                expected_origin,
                unavailable_reason,
            );
        }

        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add,
            6
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_ready,
            2,
            "old aggregate ready counter still means the pre-add normal writer produced some custom target"
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_blocked,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom,
            3
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_match,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_mismatch,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_unavailable,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_unavailable_reasons
                .missing_position,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_unavailable_reasons
                .position_output_unavailable,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_match,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_mismatch,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_unavailable,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_unavailable_reasons
                .position_output_unavailable,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_unavailable_reasons
                .missing_position,
            0
        );
    }

    #[test]
    fn exact_placeable_carrier_uncommitted_target_unavailable_reasons_use_bucket_delta() {
        let mut summary = LiveObjectUpdateRewriteSummary::default();
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_with_normal_update_custom_rewrite_unavailable_reasons
            .missing_position = 2;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_with_normal_update_custom_rewrite_unavailable_reasons
            .position_output_unavailable = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_unavailable_reasons
            .no_appearance_claim = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_normal_update_only_custom_rewrite_unavailable_reasons
            .position_output_unavailable = 3;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_pre_add_custom_update_only_custom_rewrite_unavailable_reasons
            .unique_module_target_unavailable = 1;

        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_following_normal_rewrite_target_unavailable_reasons
            .missing_position = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_following_custom_rewrite_target_unavailable_reasons
            .no_appearance_claim = 2;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_normal_rewrite_target_unavailable_reasons
            .position_output_unavailable = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_pre_add_custom_rewrite_target_unavailable_reasons
            .unique_module_target_unavailable = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_unavailable_satisfied_by_matching_carrier_reasons
            .missing_position = 1;
        summary
            .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_unavailable_satisfied_by_matching_carrier_reasons
            .position_output_unavailable = 2;

        let resolution = summary.exact_placeable_custom_carrier_target_unavailable_resolution();
        let scoped = resolution.scoped();
        let total = scoped.total();
        let selected = resolution.selected();
        let committed = resolution.committed();
        let satisfied = resolution.satisfied();
        let uncommitted = resolution.uncommitted();
        let unresolved = resolution.unresolved();
        let selected_by_scope = resolution.selected_by_scope();
        let committed_by_scope = resolution.committed_by_scope();
        let satisfied_by_scope = resolution.satisfied_by_scope();
        let uncommitted_by_scope = resolution.uncommitted_by_scope();
        let unresolved_by_scope = resolution.unresolved_by_scope();

        assert_eq!(total.selected, selected);
        assert_eq!(total.committed, committed);
        assert_eq!(total.satisfied, satisfied);
        assert_eq!(total.uncommitted, uncommitted);
        assert_eq!(total.unresolved, unresolved);
        assert_eq!(selected.total(), 8);
        assert_eq!(committed.total(), 5);
        assert_eq!(satisfied.missing_position, 1);
        assert_eq!(satisfied.position_output_unavailable, 2);
        assert_eq!(satisfied.total(), 3);
        assert_eq!(uncommitted.no_appearance_claim, 0);
        assert_eq!(uncommitted.unique_module_target_unavailable, 0);
        assert_eq!(uncommitted.missing_position, 1);
        assert_eq!(uncommitted.position_output_unavailable, 3);
        assert_eq!(uncommitted.total(), 4);
        assert_eq!(unresolved.no_appearance_claim, 0);
        assert_eq!(unresolved.unique_module_target_unavailable, 0);
        assert_eq!(unresolved.missing_position, 1);
        assert_eq!(unresolved.position_output_unavailable, 3);
        assert_eq!(unresolved.total(), 4);

        assert_eq!(selected_by_scope.following_normal.missing_position, 2);
        assert_eq!(
            scoped.following_normal.selected,
            selected_by_scope.following_normal
        );
        assert_eq!(
            selected_by_scope
                .following_normal
                .position_output_unavailable,
            1
        );
        assert_eq!(selected_by_scope.following_custom.no_appearance_claim, 1);
        assert_eq!(
            scoped.following_custom.selected,
            selected_by_scope.following_custom
        );
        assert_eq!(
            selected_by_scope.pre_add_normal.position_output_unavailable,
            3
        );
        assert_eq!(
            scoped.pre_add_normal.selected,
            selected_by_scope.pre_add_normal
        );
        assert_eq!(
            selected_by_scope
                .pre_add_custom
                .unique_module_target_unavailable,
            1
        );
        assert_eq!(
            scoped.pre_add_custom.selected,
            selected_by_scope.pre_add_custom
        );
        assert_eq!(committed_by_scope.following_normal.missing_position, 1);
        assert_eq!(
            committed_by_scope.following_custom.no_appearance_claim, 2,
            "following-custom commits saturate only their own selected scope"
        );
        assert_eq!(
            scoped.following_custom.committed,
            committed_by_scope.following_custom
        );
        assert_eq!(
            satisfied_by_scope
                .following_custom
                .position_output_unavailable,
            2
        );
        assert_eq!(
            scoped.following_custom.satisfied,
            satisfied_by_scope.following_custom
        );
        assert_eq!(
            satisfied_by_scope.total_reasons().total(),
            3,
            "matching following-custom carriers are still reported as satisfied evidence"
        );
        assert_eq!(uncommitted_by_scope.following_normal.missing_position, 1);
        assert_eq!(
            uncommitted_by_scope
                .following_normal
                .position_output_unavailable,
            1
        );
        assert_eq!(
            uncommitted_by_scope
                .pre_add_normal
                .position_output_unavailable,
            2
        );
        assert_eq!(unresolved_by_scope.following_normal.total(), 2);
        assert_eq!(
            scoped.following_normal.unresolved,
            unresolved_by_scope.following_normal
        );
        assert_eq!(
            unresolved_by_scope.following_custom.total(),
            0,
            "the satisfied matching carrier clears only following-custom target-unavailable evidence"
        );
        assert_eq!(
            scoped.following_custom.unresolved.total(),
            0,
            "the scoped resolver must keep following-custom satisfaction scope-local"
        );
        assert_eq!(unresolved_by_scope.pre_add_normal.total(), 2);
        assert_eq!(
            scoped.pre_add_normal.unresolved,
            unresolved_by_scope.pre_add_normal
        );
        assert_eq!(unresolved_by_scope.pre_add_custom.total(), 0);
        assert_eq!(
            scoped.pre_add_custom.unresolved,
            unresolved_by_scope.pre_add_custom
        );
    }

    #[test]
