    #[test]
    fn exact_placeable_add_following_split_custom_update_carrier_resolves_fixed_output_identity() {
        let object_id = 0x8000_3626u32;
        let target_resref = *b"plc_split_fwd\0\0\0";
        let z_raw = encode_ee_position_z(0.0).expect("test z should encode");

        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_POSITION_MASK.to_le_bytes());
        live.extend_from_slice(&1000u16.to_le_bytes());
        live.extend_from_slice(&2000u16.to_le_bytes());
        live.extend_from_slice(&((z_raw >> 2) as u16).to_le_bytes());

        let carrier_offset = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&target_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            false, // useable conflicts with the fixed-output-equivalent rows.
            false, // trap disarmable already matches.
            false, // lockable conflicts with the fixed-output-equivalent rows.
            false, // locked already matches.
            false, // unknown 0x1AC sibling stays packet-authored.
            true,  // name-valid stays packet-authored.
            false, // EE-only light/visual guard before the transform map.
        ]);
        fragment_bits.extend([(z_raw & 0b10) != 0, (z_raw & 0b01) != 0]);
        let mut payload = live_object_payload_from_parts(&live, &fragment_bits)
            .expect("custom A/09 followed by split position/custom U/09 payload");

        let module_state = crate::translate::area::AreaPlaceableContextState {
            static_object: true,
            useable: true,
            trap_flag: false,
            trap_disarmable: false,
            lockable: true,
            locked: false,
        };
        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 10.0,
                    y: 20.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: None,
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 10.0,
                    y: 20.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: Some(target_resref),
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
            ],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let original_len = payload.len();
        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("split following U/09 position and custom carrier should identify the add row");
        assert_eq!(summary.add_records_examined, 1);
        assert_eq!(summary.update_records_examined, 2);
        assert_eq!(summary.add_records_rewritten, 1);
        assert_eq!(summary.update_records_rewritten, 0);
        assert_eq!(summary.bytes_inserted, 0);
        assert_eq!(payload.len(), original_len);
        assert_eq!(
            summary.exact_placeable_add_identity_resolved_by_following_position_equivalence, 1,
            "the exact split U/09 position plus custom CResRef identifies the module row"
        );
        assert_eq!(
            summary
                .exact_placeable_add_identity_resolved_by_following_position_fixed_output_equivalence,
            0,
            "the split custom carrier makes this a full output proof"
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_fixed_width_unproven_carrier_skipped,
            0
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_skipped,
            1
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_with_update,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update,
            0,
            "the existing following custom U/09 carrier suppresses synthetic insertion"
        );

        let claim = claim_payload_if_verified(&payload).expect("post-rewrite split carrier claim");
        assert_eq!(claim.mentions.len(), 3);
        assert_eq!(claim.mentions[0].record_end, add_end);
        assert_eq!(claim.mentions[2].record_offset, carrier_offset);
        assert_eq!(
            claim.mentions[2].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            })
        );
    }

    #[test]
    fn following_custom_carrier_identity_requires_matching_template_resref() {
        let object_id = 0x8000_3623u32;
        let source_resref = *b"plc_fx_source\0\0\0";
        let target_resref = *b"plc_fx_target\0\0\0";
        let z_raw = encode_ee_position_z(0.0).expect("test z should encode");
        let update_mask = LEGACY_UPDATE_POSITION_MASK | LEGACY_UPDATE_APPEARANCE_MASK;

        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&update_mask.to_le_bytes());
        live.extend_from_slice(&1000u16.to_le_bytes());
        live.extend_from_slice(&2000u16.to_le_bytes());
        live.extend_from_slice(&((z_raw >> 2) as u16).to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&source_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, false, false, false, true, false, true, false, false, true, false,
        ]);
        fragment_bits.extend([(z_raw & 0b10) != 0, (z_raw & 0b01) != 0]);
        let payload = live_object_payload_from_parts(&live, &fragment_bits)
            .expect("custom A/09 plus position+appearance U/09 payload");
        let claim = claim_payload_if_verified(&payload).expect("exact custom carrier claim");
        let module_state = crate::translate::area::AreaPlaceableContextState {
            static_object: true,
            useable: true,
            trap_flag: false,
            trap_disarmable: false,
            lockable: true,
            locked: false,
        };
        let context_with_mismatch = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                object_id,
                appearance: 0xFFFE,
                x: 10.0,
                y: 20.0,
                z: 0.0,
                object_id_confidence:
                    crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                module_state: Some(module_state),
                module_template_resref: Some(target_resref),
                ..crate::translate::area::AreaPlaceableContextRow::default()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };
        assert!(
            following_update_custom_carrier_identity_match_for_add(
                &context_with_mismatch,
                object_id,
                add_end,
                &claim,
            )
            .is_none(),
            "a parser-owned U/09 carrier with the wrong CResRef must not identify the add row"
        );

        let context_with_match = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![crate::translate::area::AreaPlaceableContextRow {
                module_template_resref: Some(source_resref),
                ..context_with_mismatch.static_rows[0].clone()
            }],
            ..crate::translate::area::AreaPlaceableContext::default()
        };
        assert_eq!(
            following_update_custom_carrier_identity_match_for_add(
                &context_with_match,
                object_id,
                add_end,
                &claim,
            )
            .map(|row| row.module_template_resref),
            Some(Some(source_resref))
        );

        let context_with_divergent_outputs = crate::translate::area::AreaPlaceableContext {
            static_rows: vec![
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 10.0,
                    y: 20.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: Some(source_resref),
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 10.0,
                    y: 20.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: Some(target_resref),
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
            ],
            ..crate::translate::area::AreaPlaceableContext::default()
        };
        let blocked_carrier = exact_placeable_update_appearance_carrier_for_add(
            &context_with_divergent_outputs,
            &claim,
            object_id,
            claim.mentions[0].record_offset,
            add_end,
        );
        assert!(!blocked_carrier.following_custom_rewrite_ready());
        assert!(
            blocked_carrier.following_custom_rewrite_blocked(),
            "a custom U/09 carrier is present but not rewrite-ready when duplicate-position outputs diverge"
        );
    }

    #[test]
    fn exact_placeable_add_synthesizes_after_blocked_following_custom_carrier() {
        let object_id = 0x8000_3628u32;
        let stale_resref = *b"plc_stale_car\0\0\0";
        let target_resref = *b"plc_fixed_car\0\0\0";
        let z_raw = encode_ee_position_z(0.0).expect("test z should encode");

        let mut live = vec![b'A', PLACEABLE_OBJECT_TYPE];
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&0u32.to_le_bytes());
        live.push(5);
        live.extend_from_slice(&0x0011u16.to_le_bytes());
        live.extend_from_slice(&0u16.to_le_bytes());
        live.extend_from_slice(&visual_transform::EE_OBJECT_VISUAL_TRANSFORM_IDENTITY_BYTES);
        let add_end = live.len();

        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_POSITION_MASK.to_le_bytes());
        live.extend_from_slice(&1000u16.to_le_bytes());
        live.extend_from_slice(&2000u16.to_le_bytes());
        live.extend_from_slice(&((z_raw >> 2) as u16).to_le_bytes());

        let stale_custom_offset = live.len();
        live.extend_from_slice(&[b'U', PLACEABLE_OBJECT_TYPE]);
        live.extend_from_slice(&object_id.to_le_bytes());
        live.extend_from_slice(&LEGACY_UPDATE_APPEARANCE_MASK.to_le_bytes());
        live.extend_from_slice(&0xFFFEu16.to_le_bytes());
        live.extend_from_slice(&stale_resref);

        let mut fragment_bits = vec![false; CNW_FRAGMENT_HEADER_BITS];
        fragment_bits.extend([
            false, // direct CExoString name branch.
            false, // reputation/visual selector.
            false, // no optional object id bytes.
            false, // static/plot stays packet-authored.
            true,  // useable already matches.
            false, // trap disarmable already matches.
            true,  // lockable already matches.
            false, // locked already matches.
            false, // unknown 0x1AC sibling stays packet-authored.
            true,  // name-valid stays packet-authored.
            false, // EE-only light/visual guard before the transform map.
        ]);
        fragment_bits.extend([(z_raw & 0b10) != 0, (z_raw & 0b01) != 0]);
        let mut payload = live_object_payload_from_parts(&live, &fragment_bits)
            .expect("A/09 with following position and stale custom carrier payload");

        let module_state = crate::translate::area::AreaPlaceableContextState {
            static_object: true,
            useable: true,
            trap_flag: false,
            trap_disarmable: false,
            lockable: true,
            locked: false,
        };
        let area_context = crate::translate::area::AreaPlaceableContext {
            area_resref: "testarea".to_string(),
            static_rows: vec![
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 10.0,
                    y: 20.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: Some(target_resref),
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
                crate::translate::area::AreaPlaceableContextRow {
                    object_id,
                    appearance: 0xFFFE,
                    x: 30.0,
                    y: 40.0,
                    z: 0.0,
                    object_id_confidence:
                        crate::translate::area::AreaPlaceableContextObjectIdConfidence::DuplicateObjectId,
                    module_state: Some(module_state),
                    module_template_resref: Some(*b"plc_other_car\0\0\0"),
                    ..crate::translate::area::AreaPlaceableContextRow::default()
                },
            ],
            ..crate::translate::area::AreaPlaceableContext::default()
        };

        let pre_claim =
            claim_payload_if_verified(&payload).expect("pre-rewrite exact stale custom carrier");
        let carrier = exact_placeable_update_appearance_carrier_for_add(
            &area_context,
            &pre_claim,
            object_id,
            pre_claim.mentions[0].record_offset,
            add_end,
        );
        assert_eq!(
            carrier.synthesis_policy(&area_context.static_rows[0]),
            ExactPlaceableCustomCarrierSynthesisPolicy::SynthesizesAfterAddFollowingCustomTargetUnavailable,
            "the stale following custom U/09 is explicit later state, not the add's carrier"
        );

        let original_live_len = live.len();
        let summary = rewrite_update_records_payload_with_area_context_if_possible(
            &mut payload,
            Some(&area_context),
        )
        .expect("blocked stale custom carrier should be followed by a synthetic replacement");
        assert_eq!(summary.add_records_examined, 1);
        assert_eq!(summary.update_records_examined, 2);
        assert_eq!(summary.add_records_rewritten, 1);
        assert_eq!(summary.update_records_rewritten, 0);
        assert_eq!(
            summary.exact_placeable_add_identity_resolved_by_following_position,
            1
        );
        assert_eq!(
            summary.exact_placeable_add_module_custom_template_resref_fixed_width_with_update,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_ready,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_blocked,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_target_mismatch,
            0
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_with_custom_update_custom_rewrite_unavailable,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add,
            1
        );
        assert_eq!(
            summary
                .exact_placeable_add_module_custom_template_resref_fixed_width_synthesized_update_after_add_following_custom_rewrite_target_unavailable,
            1
        );
        assert_eq!(
            summary.bytes_inserted,
            (LEGACY_UPDATE_HEADER_BYTES
                + EE_UPDATE_APPEARANCE_WORD_READ_BYTES
                + EE_UPDATE_APPEARANCE_RESREF_READ_BYTES) as u32
        );
        assert_eq!(summary.new_live_bytes_length, original_live_len + 28);

        let claim = claim_payload_if_verified(&payload)
            .expect("post-rewrite exact stale custom plus replacement carrier payload");
        assert_eq!(claim.mentions.len(), 4);
        assert_eq!(
            claim.mentions[1].record_offset, add_end,
            "the add target carrier is inserted at the add boundary"
        );
        assert_eq!(
            claim.mentions[1].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(target_resref),
            }),
            "the add row still gets its module custom carrier"
        );
        assert_eq!(claim.mentions[3].record_offset, stale_custom_offset + 28);
        assert_eq!(
            claim.mentions[3].placeable_appearance,
            Some(LiveObjectPlaceableAppearance {
                appearance: 0xFFFE,
                resref: Some(stale_resref),
            }),
            "the later packet-authored custom U/09 remains final state"
        );
        assert_eq!(
            claim.mentions[1].fragment_bit_start, claim.mentions[0].fragment_bit_end,
            "the synthetic add carrier inherits the verified add cursor"
        );
        assert_eq!(
            claim.mentions[1].fragment_bit_end, claim.mentions[0].fragment_bit_end,
            "the appearance-only add carrier consumes no fragment bits"
        );
    }

