#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ExactPlaceableUnprovenCustomCarrierWriterGapSource {
    SourceUnblocked,
    SourceBlockedFieldRewrite,
    SourceBlockedFieldUnchanged,
}

impl ExactPlaceableUnprovenCustomCarrierWriterGapSource {
    fn from_source_and_field_outcome(source_blocked: bool, field_rewritten: bool) -> Self {
        match (source_blocked, field_rewritten) {
            (false, _) => Self::SourceUnblocked,
            (true, true) => Self::SourceBlockedFieldRewrite,
            (true, false) => Self::SourceBlockedFieldUnchanged,
        }
    }

    fn is_writer_gap_candidate(self) -> bool {
        !matches!(self, Self::SourceBlockedFieldUnchanged)
    }

    fn is_source_blocked_writer_gap(self) -> bool {
        matches!(self, Self::SourceBlockedFieldRewrite)
    }

    fn is_source_unblocked_writer_gap(self) -> bool {
        matches!(self, Self::SourceUnblocked)
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::SourceUnblocked => "source-unblocked",
            Self::SourceBlockedFieldRewrite => "source-blocked-field-rewrite",
            Self::SourceBlockedFieldUnchanged => "source-blocked-field-unchanged",
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ExactPlaceableUnprovenCustomCarrierSynthesisGate {
    EligibleSourceUnblocked,
    EligibleSourceCarriedTemplateResRef,
    BlockedSourceOwned,
    BlockedSourceProvenance,
    BlockedMissingTemplateResRef,
    BlockedDivergentOutput,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ExactPlaceableUnprovenCustomCarrierSourceTrustedGate {
    EligibleModuleTemplateResRef,
    EligibleSourceCarriedTemplateResRef,
    BlockedMissingTemplateResRef,
    BlockedSourceCarriedTemplateResRefDivergentOutput,
    BlockedDivergentOutput,
}

impl ExactPlaceableUnprovenCustomCarrierSourceTrustedGate {
    fn from_row_and_carrier(
        row: &AreaPlaceableContextRow,
        output_divergent: bool,
        carrier: ExactPlaceableUpdateAppearanceCarrier,
    ) -> Self {
        if row.module_template_resref.is_none() {
            if carrier
                .source_carried_template_resref_for_add(row)
                .is_none()
            {
                return Self::BlockedMissingTemplateResRef;
            }
            if output_divergent {
                return Self::BlockedSourceCarriedTemplateResRefDivergentOutput;
            }
            return Self::EligibleSourceCarriedTemplateResRef;
        }
        if output_divergent {
            return Self::BlockedDivergentOutput;
        }
        Self::EligibleModuleTemplateResRef
    }

    fn is_eligible(self) -> bool {
        matches!(
            self,
            Self::EligibleModuleTemplateResRef | Self::EligibleSourceCarriedTemplateResRef
        )
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::EligibleModuleTemplateResRef => "eligible-module-template-resref",
            Self::EligibleSourceCarriedTemplateResRef => "eligible-source-carried-template-resref",
            Self::BlockedMissingTemplateResRef => "blocked-missing-template-resref",
            Self::BlockedSourceCarriedTemplateResRefDivergentOutput => {
                "blocked-source-carried-template-resref-divergent-output"
            }
            Self::BlockedDivergentOutput => "blocked-divergent-output",
        }
    }
}

impl ExactPlaceableUnprovenCustomCarrierSynthesisGate {
    fn from_row_evidence(
        row_evidence: ExactPlaceableUnprovenCustomCarrierRowEvidence,
        row: &AreaPlaceableContextRow,
        output_divergent: bool,
        source_trusted_gate: ExactPlaceableUnprovenCustomCarrierSourceTrustedGate,
    ) -> Self {
        if !row_evidence.is_writer_gap_candidate() {
            return Self::BlockedSourceOwned;
        }
        if !row_evidence.source().is_source_unblocked_writer_gap() {
            return Self::BlockedSourceProvenance;
        }
        if row.module_template_resref.is_none() {
            if matches!(
                source_trusted_gate,
                ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::EligibleSourceCarriedTemplateResRef
            ) {
                return Self::EligibleSourceCarriedTemplateResRef;
            }
            if matches!(
                source_trusted_gate,
                ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedSourceCarriedTemplateResRefDivergentOutput
            ) {
                return Self::BlockedDivergentOutput;
            }
            return Self::BlockedMissingTemplateResRef;
        }
        if output_divergent {
            return Self::BlockedDivergentOutput;
        }
        Self::EligibleSourceUnblocked
    }

    fn is_synthesis_eligible(
        self,
        source_trusted_gate: ExactPlaceableUnprovenCustomCarrierSourceTrustedGate,
    ) -> bool {
        // Malformed P/04 source provenance still blocks identity proof. Once a
        // P/05 fixed-output row has rewritten fields, the source-trusted gate
        // separately proves the custom carrier has a concrete, non-divergent
        // module output, or a parser-owned pre-add custom U/09 supplied the
        // missing TemplateResRef.
        matches!(self, Self::EligibleSourceUnblocked)
            || matches!(self, Self::EligibleSourceCarriedTemplateResRef)
            || (matches!(self, Self::BlockedSourceProvenance) && source_trusted_gate.is_eligible())
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::EligibleSourceUnblocked => "eligible-source-unblocked",
            Self::EligibleSourceCarriedTemplateResRef => "eligible-source-carried-template-resref",
            Self::BlockedSourceOwned => "blocked-source-owned",
            Self::BlockedSourceProvenance => "blocked-source-provenance",
            Self::BlockedMissingTemplateResRef => "blocked-missing-template-resref",
            Self::BlockedDivergentOutput => "blocked-divergent-output",
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct ExactPlaceableUnprovenCustomCarrierRowEvidence {
    slot: ExactPlaceableUpdateAppearanceCarrierSlot,
    source: ExactPlaceableUnprovenCustomCarrierWriterGapSource,
    source_blockers: Option<AreaPlaceableSourceProvenanceBlockers>,
    field_rewritten: bool,
}

impl ExactPlaceableUnprovenCustomCarrierRowEvidence {
    fn from_update_carrier_target_and_field_outcome(
        carrier: ExactPlaceableUpdateAppearanceCarrier,
        base_target: AreaPlaceableContextStaticReconciliationTarget<'_>,
        field_rewritten: bool,
    ) -> Self {
        let source_blockers = placeable_static_target_source_provenance_blockers(base_target);
        Self {
            slot: carrier.selected_slot(),
            source:
                ExactPlaceableUnprovenCustomCarrierWriterGapSource::from_source_and_field_outcome(
                    source_blockers.is_some(),
                    field_rewritten,
                ),
            source_blockers,
            field_rewritten,
        }
    }

    fn slot(self) -> ExactPlaceableUpdateAppearanceCarrierSlot {
        self.slot
    }

    fn source(self) -> ExactPlaceableUnprovenCustomCarrierWriterGapSource {
        self.source
    }

    fn source_blockers(self) -> Option<AreaPlaceableSourceProvenanceBlockers> {
        self.source_blockers
    }

    fn is_writer_gap_candidate(self) -> bool {
        self.source.is_writer_gap_candidate()
    }

    fn record(self, summary: &mut LiveObjectUpdateRewriteSummary) {
        summary.exact_placeable_add_module_custom_fixed_width_unproven_carrier_skipped = summary
            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_skipped
            .saturating_add(1);
        if let Some(source_blockers) = self.source_blockers {
            record_exact_placeable_unproven_custom_carrier_source_blockers(
                summary,
                source_blockers,
            );
            summary
                .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocker_slots
                .record(self.slot, source_blockers);
            record_exact_placeable_unproven_custom_carrier_source_blocked_field_correlation(
                summary,
                source_blockers,
                self.field_rewritten,
            );
        }
        self.slot.record_unproven_custom_carrier(summary);
        self.slot
            .record_unproven_custom_carrier_writer_gap(summary, self.source);
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ExactPlaceableUpdateAppearanceCarrierSlot {
    FollowingNormalUpdate,
    FollowingCustomUpdate,
    PreAddNormalUpdate,
    PreAddCustomUpdate,
    AddOnly,
}

impl ExactPlaceableUpdateAppearanceCarrierSlot {
    fn from_carrier(carrier: ExactPlaceableUpdateAppearanceCarrier) -> Self {
        if let Some(selected_following) = carrier.selected_following() {
            return if selected_following.is_custom() {
                Self::FollowingCustomUpdate
            } else {
                Self::FollowingNormalUpdate
            };
        }
        if let Some(selected_pre_add) = carrier.selected_pre_add() {
            return if selected_pre_add.is_custom() {
                Self::PreAddCustomUpdate
            } else {
                Self::PreAddNormalUpdate
            };
        }
        Self::AddOnly
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::FollowingNormalUpdate => "following-normal-update",
            Self::FollowingCustomUpdate => "following-custom-update",
            Self::PreAddNormalUpdate => "pre-add-normal-update",
            Self::PreAddCustomUpdate => "pre-add-custom-update",
            Self::AddOnly => "add-only",
        }
    }

    fn record_unproven_custom_carrier(self, summary: &mut LiveObjectUpdateRewriteSummary) {
        match self {
            Self::FollowingNormalUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_update
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_normal_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_normal_update
                        .saturating_add(1);
            }
            Self::FollowingCustomUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_update
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_custom_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_with_custom_update
                        .saturating_add(1);
            }
            Self::PreAddNormalUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_update_only
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_normal_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_normal_update_only
                        .saturating_add(1);
            }
            Self::PreAddCustomUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_update_only
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_custom_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_pre_add_custom_update_only
                        .saturating_add(1);
            }
            Self::AddOnly => {
                summary.exact_placeable_add_module_custom_fixed_width_unproven_carrier_add_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_add_only
                        .saturating_add(1);
            }
        }
    }

    fn record_unproven_custom_carrier_writer_gap(
        self,
        summary: &mut LiveObjectUpdateRewriteSummary,
        source: ExactPlaceableUnprovenCustomCarrierWriterGapSource,
    ) {
        if !source.is_writer_gap_candidate() {
            return;
        }
        let source_blocked_writer_gap = source.is_source_blocked_writer_gap();
        match self {
            Self::FollowingNormalUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_update
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_normal_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_normal_update
                        .saturating_add(1);
                if source_blocked_writer_gap {
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_update =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_update
                            .saturating_add(1);
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_normal_update =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_normal_update
                            .saturating_add(1);
                }
            }
            Self::FollowingCustomUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_update
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_custom_update =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_with_custom_update
                        .saturating_add(1);
                if source_blocked_writer_gap {
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_update =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_update
                            .saturating_add(1);
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_custom_update =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_with_custom_update
                            .saturating_add(1);
                }
            }
            Self::PreAddNormalUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_update_only
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_normal_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_normal_update_only
                        .saturating_add(1);
                if source_blocked_writer_gap {
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_update_only =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_update_only
                            .saturating_add(1);
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_normal_update_only =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_normal_update_only
                            .saturating_add(1);
                }
            }
            Self::PreAddCustomUpdate => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_update_only
                        .saturating_add(1);
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_custom_update_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_pre_add_custom_update_only
                        .saturating_add(1);
                if source_blocked_writer_gap {
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_update_only =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_update_only
                            .saturating_add(1);
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_custom_update_only =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_pre_add_custom_update_only
                            .saturating_add(1);
                }
            }
            Self::AddOnly => {
                summary
                    .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_add_only =
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_writer_gap_add_only
                        .saturating_add(1);
                if source_blocked_writer_gap {
                    summary
                        .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_add_only =
                        summary
                            .exact_placeable_add_module_custom_fixed_width_unproven_carrier_source_blocked_writer_gap_add_only
                            .saturating_add(1);
                }
            }
        }
    }
}

impl ExactPlaceableUnprovenCustomCarrierWriterGapSlots {
    pub(crate) fn is_empty(self) -> bool {
        self.with_update == 0
            && self.with_normal_update == 0
            && self.with_custom_update == 0
            && self.pre_add_update_only == 0
            && self.pre_add_normal_update_only == 0
            && self.pre_add_custom_update_only == 0
            && self.add_only == 0
    }

    fn increment_slot(&mut self, slot: ExactPlaceableUpdateAppearanceCarrierSlot) {
        match slot {
            ExactPlaceableUpdateAppearanceCarrierSlot::FollowingNormalUpdate => {
                self.with_update = self.with_update.saturating_add(1);
                self.with_normal_update = self.with_normal_update.saturating_add(1);
            }
            ExactPlaceableUpdateAppearanceCarrierSlot::FollowingCustomUpdate => {
                self.with_update = self.with_update.saturating_add(1);
                self.with_custom_update = self.with_custom_update.saturating_add(1);
            }
            ExactPlaceableUpdateAppearanceCarrierSlot::PreAddNormalUpdate => {
                self.pre_add_update_only = self.pre_add_update_only.saturating_add(1);
                self.pre_add_normal_update_only = self.pre_add_normal_update_only.saturating_add(1);
            }
            ExactPlaceableUpdateAppearanceCarrierSlot::PreAddCustomUpdate => {
                self.pre_add_update_only = self.pre_add_update_only.saturating_add(1);
                self.pre_add_custom_update_only = self.pre_add_custom_update_only.saturating_add(1);
            }
            ExactPlaceableUpdateAppearanceCarrierSlot::AddOnly => {
                self.add_only = self.add_only.saturating_add(1);
            }
        }
    }

    fn saturating_add_assign(&mut self, rhs: Self) {
        self.with_update = self.with_update.saturating_add(rhs.with_update);
        self.with_normal_update = self
            .with_normal_update
            .saturating_add(rhs.with_normal_update);
        self.with_custom_update = self
            .with_custom_update
            .saturating_add(rhs.with_custom_update);
        self.pre_add_update_only = self
            .pre_add_update_only
            .saturating_add(rhs.pre_add_update_only);
        self.pre_add_normal_update_only = self
            .pre_add_normal_update_only
            .saturating_add(rhs.pre_add_normal_update_only);
        self.pre_add_custom_update_only = self
            .pre_add_custom_update_only
            .saturating_add(rhs.pre_add_custom_update_only);
        self.add_only = self.add_only.saturating_add(rhs.add_only);
    }

    fn saturating_add_slots(mut self, rhs: Self) -> Self {
        self.saturating_add_assign(rhs);
        self
    }

    fn saturating_sub_slots(self, rhs: Self) -> Self {
        Self {
            with_update: self.with_update.saturating_sub(rhs.with_update),
            with_normal_update: self
                .with_normal_update
                .saturating_sub(rhs.with_normal_update),
            with_custom_update: self
                .with_custom_update
                .saturating_sub(rhs.with_custom_update),
            pre_add_update_only: self
                .pre_add_update_only
                .saturating_sub(rhs.pre_add_update_only),
            pre_add_normal_update_only: self
                .pre_add_normal_update_only
                .saturating_sub(rhs.pre_add_normal_update_only),
            pre_add_custom_update_only: self
                .pre_add_custom_update_only
                .saturating_sub(rhs.pre_add_custom_update_only),
            add_only: self.add_only.saturating_sub(rhs.add_only),
        }
    }

    pub(crate) fn source_unblocked_by(
        self,
        source_blocked: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    ) -> Self {
        self.saturating_sub_slots(source_blocked)
    }
}

impl ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceGateSlots {
    pub(crate) fn all(self) -> ExactPlaceableUnprovenCustomCarrierWriterGapSlots {
        let mut all = self.missing_template_resref;
        all.saturating_add_assign(self.divergent_output);
        all
    }

    pub(crate) fn is_empty(self) -> bool {
        self.all().is_empty()
    }
}

impl ExactPlaceableUnprovenCustomCarrierSourceBlockerSlots {
    fn record(
        &mut self,
        slot: ExactPlaceableUpdateAppearanceCarrierSlot,
        blockers: AreaPlaceableSourceProvenanceBlockers,
    ) {
        if !blockers.any() {
            return;
        }
        self.source_blocked.increment_slot(slot);
        if blockers.read_mismatch_rows() != 0 {
            self.read_mismatch.increment_slot(slot);
        }
        if blockers.fragment_owned_rows() != 0 {
            self.fragment_owned.increment_slot(slot);
        }
        if blockers.read_mismatch_and_fragment_owned_rows() != 0 {
            self.read_mismatch_and_fragment_owned.increment_slot(slot);
        }
    }

    pub(crate) fn saturating_add_assign(&mut self, rhs: Self) {
        self.source_blocked
            .saturating_add_assign(rhs.source_blocked);
        self.read_mismatch.saturating_add_assign(rhs.read_mismatch);
        self.fragment_owned
            .saturating_add_assign(rhs.fragment_owned);
        self.read_mismatch_and_fragment_owned
            .saturating_add_assign(rhs.read_mismatch_and_fragment_owned);
    }

    fn saturating_sub_slots(self, rhs: Self) -> Self {
        Self {
            source_blocked: self.source_blocked.saturating_sub_slots(rhs.source_blocked),
            read_mismatch: self.read_mismatch.saturating_sub_slots(rhs.read_mismatch),
            fragment_owned: self.fragment_owned.saturating_sub_slots(rhs.fragment_owned),
            read_mismatch_and_fragment_owned: self
                .read_mismatch_and_fragment_owned
                .saturating_sub_slots(rhs.read_mismatch_and_fragment_owned),
        }
    }
}

impl ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceBlockerSlots {
    fn record(
        &mut self,
        slot: ExactPlaceableUpdateAppearanceCarrierSlot,
        source_trusted_gate: ExactPlaceableUnprovenCustomCarrierSourceTrustedGate,
        blockers: AreaPlaceableSourceProvenanceBlockers,
    ) {
        match source_trusted_gate {
            ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::EligibleModuleTemplateResRef
            | ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::EligibleSourceCarriedTemplateResRef => {}
            ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedMissingTemplateResRef => {
                self.missing_template_resref.record(slot, blockers);
            }
            ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedSourceCarriedTemplateResRefDivergentOutput
            | ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedDivergentOutput => {
                self.divergent_output.record(slot, blockers);
            }
        }
    }

    pub(crate) fn saturating_add_assign(&mut self, rhs: Self) {
        self.missing_template_resref
            .saturating_add_assign(rhs.missing_template_resref);
        self.divergent_output
            .saturating_add_assign(rhs.divergent_output);
    }
}

impl ExactPlaceableUnprovenCustomCarrierSynthesisResolution {
    pub(crate) fn from_gate_slots(
        slots: ExactPlaceableUnprovenCustomCarrierSynthesisGateSlots,
    ) -> Self {
        let source_provenance_synthesized = slots.blocked_source_provenance_source_trusted_eligible;
        let source_provenance_synthesized_source_carried_template_resref =
            slots.blocked_source_provenance_source_trusted_source_carried_template_resref;
        let source_provenance_synthesized_module_template_resref = source_provenance_synthesized
            .saturating_sub_slots(source_provenance_synthesized_source_carried_template_resref);
        let residual_source_provenance = slots.residual_source_provenance_after_source_trusted();
        let source_unblocked_source_carried_template_resref_blocked_divergent_output =
            slots.blocked_divergent_output_source_carried_template_resref;
        let source_provenance_source_carried_template_resref_blocked_divergent_output =
            slots.blocked_source_provenance_source_trusted_source_carried_divergent_output;
        let source_provenance_source_carried_template_resref_blocked_divergent_output_blockers =
            slots
                .blocked_source_provenance_source_trusted_source_carried_divergent_output_blocker_slots;
        let source_carried_template_resref_blocked_divergent_output =
            source_unblocked_source_carried_template_resref_blocked_divergent_output
                .saturating_add_slots(
                    source_provenance_source_carried_template_resref_blocked_divergent_output,
                );
        debug_assert_eq!(
            source_provenance_synthesized_module_template_resref.saturating_add_slots(
                source_provenance_synthesized_source_carried_template_resref,
            ),
            source_provenance_synthesized
        );
        debug_assert_eq!(
            source_provenance_synthesized.saturating_add_slots(residual_source_provenance.all()),
            slots.blocked_source_provenance
        );
        debug_assert_eq!(
            residual_source_provenance
                .divergent_output
                .saturating_sub_slots(
                    source_provenance_source_carried_template_resref_blocked_divergent_output,
                )
                .saturating_add_slots(
                    source_provenance_source_carried_template_resref_blocked_divergent_output,
                ),
            residual_source_provenance.divergent_output
        );
        Self {
            eligible_source_unblocked: slots.eligible_source_unblocked,
            eligible_source_carried_template_resref: slots.eligible_source_carried_template_resref,
            source_provenance_synthesized_module_template_resref,
            source_provenance_synthesized_source_carried_template_resref,
            residual_source_provenance,
            residual_source_provenance_blockers: slots.residual_source_provenance_blocker_slots,
            source_unblocked_source_carried_template_resref_blocked_divergent_output,
            source_provenance_source_carried_template_resref_blocked_divergent_output,
            source_provenance_source_carried_template_resref_blocked_divergent_output_blockers,
            source_carried_template_resref_blocked_divergent_output,
        }
    }

    pub(crate) fn source_provenance_synthesized(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierWriterGapSlots {
        self.source_provenance_synthesized_module_template_resref
            .saturating_add_slots(self.source_provenance_synthesized_source_carried_template_resref)
    }

    pub(crate) fn source_carried_template_resref_synthesized(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierWriterGapSlots {
        self.eligible_source_carried_template_resref
            .saturating_add_slots(self.source_provenance_synthesized_source_carried_template_resref)
    }

    pub(crate) fn residual_source_provenance_after_source_carried_divergence(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceGateSlots {
        ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceGateSlots {
            missing_template_resref: self.residual_source_provenance.missing_template_resref,
            divergent_output: self
                .residual_source_provenance
                .divergent_output
                .saturating_sub_slots(
                    self.source_provenance_source_carried_template_resref_blocked_divergent_output,
                ),
        }
    }

    pub(crate) fn residual_source_provenance_blockers_after_source_carried_divergence(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceBlockerSlots {
        ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceBlockerSlots {
            missing_template_resref: self.residual_source_provenance_blockers.missing_template_resref,
            divergent_output: self
                .residual_source_provenance_blockers
                .divergent_output
                .saturating_sub_slots(
                    self.source_provenance_source_carried_template_resref_blocked_divergent_output_blockers,
                ),
        }
    }
}

impl ExactPlaceableUnprovenCustomCarrierSynthesisGateSlots {
    pub(crate) fn residual_source_provenance_after_source_trusted(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceGateSlots {
        let residual = ExactPlaceableUnprovenCustomCarrierResidualSourceProvenanceGateSlots {
            missing_template_resref: self
                .blocked_source_provenance_source_trusted_missing_template_resref,
            divergent_output: self.blocked_source_provenance_source_trusted_divergent_output,
        };
        debug_assert_eq!(
            residual.all(),
            self.blocked_source_provenance
                .saturating_sub_slots(self.blocked_source_provenance_source_trusted_eligible)
        );
        residual
    }

    pub(crate) fn remaining_blocked_source_provenance_after_source_trusted(
        self,
    ) -> ExactPlaceableUnprovenCustomCarrierWriterGapSlots {
        self.residual_source_provenance_after_source_trusted().all()
    }

    fn record(
        &mut self,
        row_evidence: ExactPlaceableUnprovenCustomCarrierRowEvidence,
        gate: ExactPlaceableUnprovenCustomCarrierSynthesisGate,
        source_trusted_gate: ExactPlaceableUnprovenCustomCarrierSourceTrustedGate,
    ) {
        let slot = row_evidence.slot();
        match gate {
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::EligibleSourceUnblocked => {
                self.eligible_source_unblocked.increment_slot(slot);
            }
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::EligibleSourceCarriedTemplateResRef => {
                self.eligible_source_carried_template_resref
                    .increment_slot(slot);
            }
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::BlockedSourceOwned => {
                self.blocked_source_owned.increment_slot(slot);
            }
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::BlockedSourceProvenance => {
                self.blocked_source_provenance.increment_slot(slot);
                match source_trusted_gate {
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::EligibleModuleTemplateResRef => {
                        self.blocked_source_provenance_source_trusted_eligible
                            .increment_slot(slot);
                    }
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::EligibleSourceCarriedTemplateResRef => {
                        self.blocked_source_provenance_source_trusted_eligible
                            .increment_slot(slot);
                        self.blocked_source_provenance_source_trusted_source_carried_template_resref
                            .increment_slot(slot);
                    }
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedMissingTemplateResRef => {
                        self.blocked_source_provenance_source_trusted_missing_template_resref
                            .increment_slot(slot);
                    }
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedDivergentOutput => {
                        self.blocked_source_provenance_source_trusted_divergent_output
                            .increment_slot(slot);
                    }
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedSourceCarriedTemplateResRefDivergentOutput => {
                        self.blocked_source_provenance_source_trusted_divergent_output
                            .increment_slot(slot);
                        self.blocked_source_provenance_source_trusted_source_carried_divergent_output
                            .increment_slot(slot);
                        if let Some(blockers) = row_evidence.source_blockers() {
                            self.blocked_source_provenance_source_trusted_source_carried_divergent_output_blocker_slots
                                .record(slot, blockers);
                        }
                    }
                }
                if let Some(blockers) = row_evidence.source_blockers() {
                    self.residual_source_provenance_blocker_slots.record(
                        slot,
                        source_trusted_gate,
                        blockers,
                    );
                    if blockers.read_mismatch_rows() != 0 {
                        self.blocked_source_provenance_read_mismatch
                            .increment_slot(slot);
                    }
                    if blockers.fragment_owned_rows() != 0 {
                        self.blocked_source_provenance_fragment_owned
                            .increment_slot(slot);
                    }
                    if blockers.read_mismatch_and_fragment_owned_rows() != 0 {
                        self.blocked_source_provenance_read_mismatch_and_fragment_owned
                            .increment_slot(slot);
                    }
                }
            }
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::BlockedMissingTemplateResRef => {
                self.blocked_missing_template_resref.increment_slot(slot);
            }
            ExactPlaceableUnprovenCustomCarrierSynthesisGate::BlockedDivergentOutput => {
                self.blocked_divergent_output.increment_slot(slot);
                if matches!(
                    source_trusted_gate,
                    ExactPlaceableUnprovenCustomCarrierSourceTrustedGate::BlockedSourceCarriedTemplateResRefDivergentOutput
                ) {
                    self.blocked_divergent_output_source_carried_template_resref
                        .increment_slot(slot);
                }
            }
        }
    }

    pub(crate) fn saturating_add_assign(&mut self, rhs: Self) {
        self.eligible_source_unblocked
            .saturating_add_assign(rhs.eligible_source_unblocked);
        self.eligible_source_carried_template_resref
            .saturating_add_assign(rhs.eligible_source_carried_template_resref);
        self.blocked_source_owned
            .saturating_add_assign(rhs.blocked_source_owned);
        self.blocked_source_provenance
            .saturating_add_assign(rhs.blocked_source_provenance);
        self.blocked_source_provenance_read_mismatch
            .saturating_add_assign(rhs.blocked_source_provenance_read_mismatch);
        self.blocked_source_provenance_fragment_owned
            .saturating_add_assign(rhs.blocked_source_provenance_fragment_owned);
        self.blocked_source_provenance_read_mismatch_and_fragment_owned
            .saturating_add_assign(rhs.blocked_source_provenance_read_mismatch_and_fragment_owned);
        self.blocked_source_provenance_source_trusted_eligible
            .saturating_add_assign(rhs.blocked_source_provenance_source_trusted_eligible);
        self.blocked_source_provenance_source_trusted_source_carried_template_resref
            .saturating_add_assign(
                rhs.blocked_source_provenance_source_trusted_source_carried_template_resref,
            );
        self.blocked_source_provenance_source_trusted_missing_template_resref
            .saturating_add_assign(
                rhs.blocked_source_provenance_source_trusted_missing_template_resref,
            );
        self.blocked_source_provenance_source_trusted_divergent_output
            .saturating_add_assign(rhs.blocked_source_provenance_source_trusted_divergent_output);
        self.blocked_source_provenance_source_trusted_source_carried_divergent_output
            .saturating_add_assign(
                rhs.blocked_source_provenance_source_trusted_source_carried_divergent_output,
            );
        self.blocked_source_provenance_source_trusted_source_carried_divergent_output_blocker_slots
            .saturating_add_assign(
                rhs.blocked_source_provenance_source_trusted_source_carried_divergent_output_blocker_slots,
            );
        self.residual_source_provenance_blocker_slots
            .saturating_add_assign(rhs.residual_source_provenance_blocker_slots);
        self.blocked_missing_template_resref
            .saturating_add_assign(rhs.blocked_missing_template_resref);
        self.blocked_divergent_output
            .saturating_add_assign(rhs.blocked_divergent_output);
        self.blocked_divergent_output_source_carried_template_resref
            .saturating_add_assign(rhs.blocked_divergent_output_source_carried_template_resref);
    }
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub struct ExactPlaceableUnprovenCustomCarrierWriterGapSlotSummary {
    pub all: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub source_blocked: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub source_unblocked: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
}

impl ExactPlaceableUnprovenCustomCarrierWriterGapSlotSummary {
    pub(crate) fn from_slots(
        all: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
        source_blocked: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    ) -> Self {
        Self {
            all,
            source_blocked,
            source_unblocked: all.source_unblocked_by(source_blocked),
        }
    }
}

#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
pub struct ExactPlaceableUnprovenCustomCarrierSlotDisposition {
    pub skipped: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub source_owned_without_field_rewrite: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub writer_gap: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub source_blocked_field_rewrite: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    pub source_unblocked: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
}

impl ExactPlaceableUnprovenCustomCarrierSlotDisposition {
    pub(crate) fn from_slots(
        skipped: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
        writer_gap: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
        source_blocked_field_rewrite: ExactPlaceableUnprovenCustomCarrierWriterGapSlots,
    ) -> Self {
        Self {
            skipped,
            source_owned_without_field_rewrite: skipped.saturating_sub_slots(writer_gap),
            writer_gap,
            source_blocked_field_rewrite,
            source_unblocked: writer_gap.source_unblocked_by(source_blocked_field_rewrite),
        }
    }
}

