#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PlaceableCustomAppearanceUpdateBatchClaimReject {
    PayloadBuild,
    Header,
    DeclaredLength,
    FragmentBits,
    Boundary,
    RecordValidator,
    Cursor,
}

#[derive(Debug, Clone, Copy)]
struct EmittedPlaceableCustomAppearanceUpdate {
    insert_offset: usize,
    sequence: usize,
    update: PendingPlaceableCustomAppearanceUpdate,
    bytes_inserted: usize,
}

impl EmittedPlaceableCustomAppearanceUpdate {
    fn final_insert_offset(self, emitted: &[Self]) -> usize {
        final_synthesized_placeable_custom_appearance_update_offset(
            self.insert_offset,
            self.sequence,
            emitted,
        )
    }

    fn record_end(self, emitted: &[Self]) -> usize {
        self.final_insert_offset(emitted)
            .saturating_add(self.bytes_inserted)
    }
}

#[derive(Debug, Clone, Copy, Default)]
struct PlaceableCustomAppearanceUpdateBatchFootprint {
    placeable_add_anchor: bool,
    normal_update_anchor: bool,
    custom_update_anchor: bool,
    after_add_origin: bool,
}

impl PlaceableCustomAppearanceUpdateBatchFootprint {
    fn from_emitted(emitted: &[EmittedPlaceableCustomAppearanceUpdate]) -> Self {
        let mut footprint = Self::default();
        for emitted_update in emitted {
            match emitted_update.update.anchor.expected_record {
                PlaceableCustomAppearanceUpdateAnchorRecord::PlaceableAdd => {
                    footprint.placeable_add_anchor = true;
                }
                PlaceableCustomAppearanceUpdateAnchorRecord::NormalAppearanceUpdate => {
                    footprint.normal_update_anchor = true;
                }
                PlaceableCustomAppearanceUpdateAnchorRecord::CustomAppearanceUpdate => {
                    footprint.custom_update_anchor = true;
                }
            }
            if emitted_update.update.insertion_origin.is_after_add() {
                footprint.after_add_origin = true;
            }
        }
        footprint
    }
}

#[derive(Debug, Clone, Copy)]
struct PlaceableCustomAppearanceUpdateBatchRejectFocus {
    kind: PlaceableCustomAppearanceUpdateBatchRejectFocusKind,
    insert_offset: usize,
    sequence: usize,
    record_end: usize,
    update: PendingPlaceableCustomAppearanceUpdate,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PlaceableCustomAppearanceUpdateBatchRejectFocusKind {
    BeforeSynthesizedUpdate,
    InsideSynthesizedUpdate,
    AfterSynthesizedUpdate,
}

impl PlaceableCustomAppearanceUpdateBatchRejectFocusKind {
    fn as_str(self) -> &'static str {
        match self {
            Self::BeforeSynthesizedUpdate => "before-synthesized-update",
            Self::InsideSynthesizedUpdate => "inside-synthesized-update",
            Self::AfterSynthesizedUpdate => "after-synthesized-update",
        }
    }
}

impl PlaceableCustomAppearanceUpdateBatchClaimReject {
    fn from_claim_reject(reject: LiveObjectPayloadClaimReject) -> Self {
        match reject.stage {
            LiveObjectPayloadClaimRejectStage::Header => Self::Header,
            LiveObjectPayloadClaimRejectStage::DeclaredLength => Self::DeclaredLength,
            LiveObjectPayloadClaimRejectStage::FragmentBits
            | LiveObjectPayloadClaimRejectStage::EmptyPayloadFragmentBits => Self::FragmentBits,
            LiveObjectPayloadClaimRejectStage::LiveGuiBoundary
            | LiveObjectPayloadClaimRejectStage::SubmessageBoundary
            | LiveObjectPayloadClaimRejectStage::NonAdvancingBoundary => Self::Boundary,
            LiveObjectPayloadClaimRejectStage::RecordValidator => Self::RecordValidator,
            LiveObjectPayloadClaimRejectStage::DeleteFragmentBits
            | LiveObjectPayloadClaimRejectStage::LiveCursor
            | LiveObjectPayloadClaimRejectStage::FragmentCursor => Self::Cursor,
        }
    }

    fn as_str(self) -> &'static str {
        match self {
            Self::PayloadBuild => "payload-build",
            Self::Header => "header",
            Self::DeclaredLength => "declared-length",
            Self::FragmentBits => "fragment-bits",
            Self::Boundary => "boundary",
            Self::RecordValidator => "record-validator",
            Self::Cursor => "cursor",
        }
    }
}

