#[derive(Debug, Clone)]
struct LiveObjectRewriteBitLedger {
    source_bit_cursor: usize,
    source_bits: Vec<bool>,
    entries: Vec<LiveObjectRewriteBitLedgerEntry>,
}

impl LiveObjectRewriteBitLedger {
    fn new() -> Self {
        Self {
            source_bit_cursor: CNW_FRAGMENT_HEADER_BITS,
            source_bits: Vec::new(),
            entries: Vec::new(),
        }
    }

    fn with_source_bits(source_bits: &[bool]) -> Self {
        Self {
            source_bit_cursor: CNW_FRAGMENT_HEADER_BITS,
            source_bits: source_bits.to_vec(),
            entries: Vec::new(),
        }
    }

    fn insert_source_bits_at_cursor(&mut self, source_bits: &[bool]) -> bool {
        self.insert_source_bits_at(self.source_bit_cursor, source_bits)
    }

    fn insert_source_bits_at(&mut self, source_bit_cursor: usize, source_bits: &[bool]) -> bool {
        if source_bits.is_empty() {
            return true;
        }
        if source_bit_cursor < self.source_bit_cursor || source_bit_cursor > self.source_bits.len()
        {
            return false;
        }
        self.source_bits.splice(
            source_bit_cursor..source_bit_cursor,
            source_bits.iter().copied(),
        );
        true
    }

    fn insert_promoted_source_bits_from_fragment(
        &mut self,
        fragment_bits: &[bool],
        bit_cursor: usize,
        bits_promoted: usize,
    ) -> bool {
        if bits_promoted == 0 {
            return true;
        }
        let Some(end) = bit_cursor.checked_add(bits_promoted) else {
            return false;
        };
        let Some(promoted_bits) = fragment_bits.get(bit_cursor..end) else {
            return false;
        };
        self.insert_source_bits_at_cursor(promoted_bits)
    }

    fn insert_promoted_source_bits_from_fragment_relative(
        &mut self,
        fragment_bits: &[bool],
        record_start_bit_cursor: usize,
        promoted_bit_cursor: usize,
        bits_promoted: usize,
    ) -> bool {
        if bits_promoted == 0 {
            return true;
        }
        let Some(prefix_source_delta) = promoted_bit_cursor.checked_sub(record_start_bit_cursor)
        else {
            return false;
        };
        let Some(source_bit_cursor) = self.source_bit_cursor.checked_add(prefix_source_delta)
        else {
            return false;
        };
        let Some(end) = promoted_bit_cursor.checked_add(bits_promoted) else {
            return false;
        };
        let Some(promoted_bits) = fragment_bits.get(promoted_bit_cursor..end) else {
            return false;
        };
        self.insert_source_bits_at(source_bit_cursor, promoted_bits)
    }

    fn commit_record(
        &mut self,
        live_bytes: &[u8],
        commit: LiveObjectRewriteBitLedgerCommit,
    ) -> bool {
        let Some(source_delta) = commit.source_delta() else {
            return false;
        };
        let source_bit_start = self.source_bit_cursor;
        let Some(source_bit_end) = source_bit_start.checked_add(source_delta) else {
            return false;
        };
        if !self.source_bits.is_empty() && source_bit_end > self.source_bits.len() {
            return false;
        }

        self.source_bit_cursor = source_bit_end;
        self.entries.push(LiveObjectRewriteBitLedgerEntry {
            offset: commit.offset,
            record_end: commit.record_end,
            opcode: live_bytes.get(commit.offset).copied().unwrap_or_default(),
            marker: live_bytes
                .get(commit.offset + 1)
                .copied()
                .unwrap_or_default(),
            source_bit_start,
            source_bit_end,
            emitted_bit_start: commit.emitted_bit_start,
            emitted_bit_end: commit.emitted_bit_end,
            bits_inserted: commit.bits_inserted,
            bits_removed: commit.bits_removed,
            family: commit.family,
        });
        true
    }

    #[cfg(test)]
    fn entries(&self) -> &[LiveObjectRewriteBitLedgerEntry] {
        &self.entries
    }

    fn recent_entries(&self, limit: usize) -> &[LiveObjectRewriteBitLedgerEntry] {
        let start = self.entries.len().saturating_sub(limit);
        &self.entries[start..]
    }

    #[cfg(test)]
    fn source_bit_cursor(&self) -> usize {
        self.source_bit_cursor
    }

    fn emitted_bit_start_for_row(&self, offset: usize, record_end: usize) -> Option<usize> {
        self.entries
            .iter()
            .find(|entry| entry.offset == offset && entry.record_end == record_end)
            .or_else(|| self.entries.iter().find(|entry| entry.offset == offset))
            .map(|entry| entry.emitted_bit_start)
    }

    fn entry_for_row(
        &self,
        offset: usize,
        record_end: usize,
    ) -> Option<&LiveObjectRewriteBitLedgerEntry> {
        self.entries
            .iter()
            .find(|entry| entry.offset == offset && entry.record_end == record_end)
            .or_else(|| self.entries.iter().find(|entry| entry.offset == offset))
    }

    fn gap_before_cursor(&self, cursor: usize) -> Option<LiveObjectRewriteBitLedgerCursorGap> {
        let previous_index = self.previous_entry_index_for_cursor(cursor)?;
        let previous = self.entries.get(previous_index)?;
        let relation = if cursor < previous.emitted_bit_start {
            "before-ledger-row"
        } else if cursor < previous.emitted_bit_end {
            "inside-previous-emitted-row"
        } else if cursor == previous.emitted_bit_end {
            "after-previous-emitted-end"
        } else {
            "unowned-emitted-gap"
        };
        let emitted_gap_bits = cursor.saturating_sub(previous.emitted_bit_end);
        let cumulative_emitted_source_delta =
            signed_bit_delta(previous.emitted_bit_end, previous.source_bit_end);
        let implied_source_cursor =
            emitted_cursor_to_source_cursor(cursor, cumulative_emitted_source_delta);
        let source_relation = if implied_source_cursor < previous.source_bit_start {
            "before-ledger-source-row"
        } else if implied_source_cursor < previous.source_bit_end {
            "inside-previous-source-row"
        } else if implied_source_cursor == previous.source_bit_end {
            "after-previous-source-end"
        } else {
            "unowned-source-gap"
        };
        let source_gap_bits = implied_source_cursor.saturating_sub(previous.source_bit_end);
        let (emitted_gap_bit_start, emitted_gap_bit_end) = if cursor > previous.emitted_bit_end {
            (previous.emitted_bit_end, cursor)
        } else {
            (cursor, cursor)
        };
        let (source_gap_bit_start, source_gap_bit_end) =
            if implied_source_cursor > previous.source_bit_end {
                (previous.source_bit_end, implied_source_cursor)
            } else {
                (implied_source_cursor, implied_source_cursor)
            };
        Some(LiveObjectRewriteBitLedgerCursorGap {
            previous_offset: previous.offset,
            previous_record_end: previous.record_end,
            previous_family: previous.family,
            previous_source_bit_start: previous.source_bit_start,
            previous_source_bit_end: previous.source_bit_end,
            previous_emitted_bit_start: previous.emitted_bit_start,
            previous_emitted_bit_end: previous.emitted_bit_end,
            cursor,
            emitted_gap_bits,
            emitted_gap_bit_start,
            emitted_gap_bit_end,
            source_emitted_delta_after_previous: signed_bit_delta(cursor, previous.source_bit_end),
            cumulative_emitted_source_delta,
            implied_source_cursor,
            source_gap_bits,
            source_gap_bit_start,
            source_gap_bit_end,
            relation,
            source_relation,
        })
    }

    fn emitted_gap_values<'a>(
        &self,
        fragment_bits: &'a [bool],
        gap: &LiveObjectRewriteBitLedgerCursorGap,
    ) -> &'a [bool] {
        fragment_bits
            .get(gap.emitted_gap_bit_start..gap.emitted_gap_bit_end)
            .unwrap_or(&[])
    }

    fn source_gap_values<'a>(
        &'a self,
        fragment_bits: &'a [bool],
        gap: &LiveObjectRewriteBitLedgerCursorGap,
    ) -> &'a [bool] {
        let source_bits = if self.source_bits.is_empty() {
            fragment_bits
        } else {
            &self.source_bits
        };
        source_bits
            .get(gap.source_gap_bit_start..gap.source_gap_bit_end)
            .unwrap_or(&[])
    }

    fn emitted_values_for_entry<'a>(
        &self,
        fragment_bits: &'a [bool],
        entry: &LiveObjectRewriteBitLedgerEntry,
    ) -> &'a [bool] {
        fragment_bits
            .get(entry.emitted_bit_start..entry.emitted_bit_end)
            .unwrap_or(&[])
    }

    fn source_values_for_entry<'a>(
        &'a self,
        fragment_bits: &'a [bool],
        entry: &LiveObjectRewriteBitLedgerEntry,
    ) -> &'a [bool] {
        let source_bits = if self.source_bits.is_empty() {
            fragment_bits
        } else {
            &self.source_bits
        };
        source_bits
            .get(entry.source_bit_start..entry.source_bit_end)
            .unwrap_or(&[])
    }

    fn source_values_for_range<'a>(
        &'a self,
        fragment_bits: &'a [bool],
        bit_start: usize,
        bit_end: usize,
    ) -> &'a [bool] {
        let source_bits = if self.source_bits.is_empty() {
            fragment_bits
        } else {
            &self.source_bits
        };
        source_bits.get(bit_start..bit_end).unwrap_or(&[])
    }

    fn source_bit_len(&self, fragment_bits: &[bool]) -> usize {
        if self.source_bits.is_empty() {
            fragment_bits.len()
        } else {
            self.source_bits.len()
        }
    }

    fn source_bits<'a>(&'a self, fragment_bits: &'a [bool]) -> &'a [bool] {
        if self.source_bits.is_empty() {
            fragment_bits
        } else {
            &self.source_bits
        }
    }

    fn source_cursor_for_emitted_cursor(&self, cursor: usize) -> usize {
        self.gap_before_cursor(cursor)
            .map(|gap| gap.implied_source_cursor)
            .unwrap_or(cursor)
    }

    fn item_update_cursor_failure_kind(&self, cursor: usize) -> LiveObjectUpdateRewriteFailureKind {
        match live_object_item_update_cursor_handoff_verdict(self, cursor).source_owner {
            LiveObjectUpdateItemCursorSourceOwner::NoLedger => {
                LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorWithoutLedger
            }
            LiveObjectUpdateItemCursorSourceOwner::BeforeLedgerRow => {
                LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorBeforeLedgerRow
            }
            LiveObjectUpdateItemCursorSourceOwner::InsidePreviousRow => {
                LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorInsideLedgerRow
            }
            LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedGap
            | LiveObjectUpdateItemCursorSourceOwner::UnownedSourceGap
            | LiveObjectUpdateItemCursorSourceOwner::UnownedEmittedAndSourceGap => {
                LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterUnownedLedgerGap
            }
            LiveObjectUpdateItemCursorSourceOwner::ContiguousTail => {
                LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterLedgerHandoff
            }
        }
    }

    fn item_update_cursor_failure_kind_with_unowned_neighbor(
        &self,
        cursor: usize,
        unowned_neighbor: Option<LiveObjectItemUpdateUnownedNeighbor>,
        source_window: Option<LiveObjectUpdateSourceWindowEvidence>,
        focus_offset: usize,
        focus_record_end: usize,
    ) -> LiveObjectUpdateRewriteFailureKind {
        let kind = self.item_update_cursor_failure_kind(cursor);
        if unowned_neighbor.is_some()
            && kind == LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorAfterLedgerHandoff
        {
            if unowned_neighbor.map(|neighbor| {
                live_object_item_handoff_classification(
                    source_window,
                    focus_offset,
                    focus_record_end,
                    neighbor,
                )
                .source_decision
            }) == Some(LiveObjectUpdateItemHandoffSourceDecision::BlockedFocusRowPrefix)
            {
                return LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorBeforeValidNeighborFocusRowPrefix;
            }
            LiveObjectUpdateRewriteFailureKind::ItemUpdateCursorBeforeValidNeighborUnownedGap
        } else {
            kind
        }
    }

    fn previous_entry_index_for_cursor(&self, cursor: usize) -> Option<usize> {
        self.entries
            .iter()
            .rposition(|entry| entry.emitted_bit_start < cursor && cursor < entry.emitted_bit_end)
            .or_else(|| {
                self.entries
                    .iter()
                    .rposition(|entry| entry.emitted_bit_end <= cursor)
            })
            .or_else(|| (!self.entries.is_empty()).then_some(0))
    }

    fn contiguous_tail_before_cursor(
        &self,
        cursor: usize,
    ) -> Option<LiveObjectRewriteBitLedgerContiguousTail> {
        let end_index = self.previous_entry_index_for_cursor(cursor)?;
        let mut start_index = end_index;
        while start_index > 0 {
            let previous = self.entries.get(start_index - 1)?;
            let current = self.entries.get(start_index)?;
            if previous.emitted_bit_end != current.emitted_bit_start
                || previous.source_bit_end != current.source_bit_start
            {
                break;
            }
            start_index -= 1;
        }

        let first = self.entries.get(start_index)?;
        let last = self.entries.get(end_index)?;
        Some(LiveObjectRewriteBitLedgerContiguousTail {
            start_index,
            end_index,
            entry_count: end_index.saturating_sub(start_index).saturating_add(1),
            source_bit_start: first.source_bit_start,
            source_bit_end: last.source_bit_end,
            emitted_bit_start: first.emitted_bit_start,
            emitted_bit_end: last.emitted_bit_end,
            emitted_gap_to_cursor: cursor.saturating_sub(last.emitted_bit_end),
            source_gap_to_cursor: emitted_cursor_to_source_cursor(
                cursor,
                signed_bit_delta(last.emitted_bit_end, last.source_bit_end),
            )
            .saturating_sub(last.source_bit_end),
        })
    }

    fn contiguous_tail_family_chain(
        &self,
        tail: LiveObjectRewriteBitLedgerContiguousTail,
    ) -> String {
        self.contiguous_tail_entries(tail)
            .iter()
            .map(|entry| entry.family)
            .collect::<Vec<_>>()
            .join("->")
    }

    fn contiguous_tail_row_chain(&self, tail: LiveObjectRewriteBitLedgerContiguousTail) -> String {
        let rows = self
            .contiguous_tail_entries(tail)
            .iter()
            .map(|entry| {
                format!(
                    "{}..{}:{}[src={}..{},emit={}..{},+{},-{}]",
                    entry.offset,
                    entry.record_end,
                    entry.family,
                    entry.source_bit_start,
                    entry.source_bit_end,
                    entry.emitted_bit_start,
                    entry.emitted_bit_end,
                    entry.bits_inserted,
                    entry.bits_removed
                )
            })
            .collect::<Vec<_>>();
        if rows.is_empty() {
            "none".to_string()
        } else {
            rows.join("->")
        }
    }

    fn contiguous_tail_entries(
        &self,
        tail: LiveObjectRewriteBitLedgerContiguousTail,
    ) -> &[LiveObjectRewriteBitLedgerEntry] {
        self.entries
            .get(tail.start_index..=tail.end_index)
            .unwrap_or(&[])
    }

    fn contiguous_tail_evidence(
        &self,
        fragment_bits: &[bool],
        cursor: usize,
    ) -> Option<LiveObjectUpdateRewriteTailEvidence> {
        let tail = self.contiguous_tail_before_cursor(cursor)?;
        let tail_entries = self.contiguous_tail_entries(tail);
        let retain_start = tail_entries
            .len()
            .saturating_sub(LIVE_OBJECT_UPDATE_REWRITE_TAIL_EVIDENCE_ENTRY_LIMIT);
        let retained_entries = &tail_entries[retain_start..];
        let mut entries = [None; LIVE_OBJECT_UPDATE_REWRITE_TAIL_EVIDENCE_ENTRY_LIMIT];
        for (slot, entry) in entries.iter_mut().zip(retained_entries.iter()) {
            let source_values = self.source_values_for_entry(fragment_bits, entry);
            let emitted_values = self.emitted_values_for_entry(fragment_bits, entry);
            *slot = Some(LiveObjectUpdateRewriteTailEntryEvidence {
                offset: entry.offset,
                record_end: entry.record_end,
                opcode: entry.opcode,
                marker: entry.marker,
                source_bit_start: entry.source_bit_start,
                source_bit_end: entry.source_bit_end,
                emitted_bit_start: entry.emitted_bit_start,
                emitted_bit_end: entry.emitted_bit_end,
                bits_inserted: entry.bits_inserted,
                bits_removed: entry.bits_removed,
                family: entry.family,
                source_bits: live_object_rewrite_bit_slice_evidence(
                    entry.source_bit_start,
                    entry.source_bit_end,
                    source_values,
                ),
                emitted_bits: live_object_rewrite_bit_slice_evidence(
                    entry.emitted_bit_start,
                    entry.emitted_bit_end,
                    emitted_values,
                ),
            });
        }
        let source_cursor = tail
            .source_bit_end
            .saturating_add(tail.source_gap_to_cursor);
        Some(LiveObjectUpdateRewriteTailEvidence {
            entry_count: tail.entry_count,
            entries_retained: retained_entries.len(),
            source_bit_start: tail.source_bit_start,
            source_bit_end: tail.source_bit_end,
            emitted_bit_start: tail.emitted_bit_start,
            emitted_bit_end: tail.emitted_bit_end,
            emitted_cursor: cursor,
            source_cursor,
            emitted_source_delta: signed_bit_delta(cursor, source_cursor),
            emitted_gap_to_cursor: tail.emitted_gap_to_cursor,
            source_gap_to_cursor: tail.source_gap_to_cursor,
            entries,
        })
    }

    fn terminal_fragment_handoff_correlation_evidence(
        &self,
        live_bytes: &[u8],
        source_bits: &[bool],
        anchored_source_bit_cursor: usize,
        focus_offset: usize,
    ) -> Option<LiveObjectUpdateTerminalFragmentHandoffCorrelationEvidence> {
        const RECENT_LEDGER_ENTRY_LIMIT: usize =
            LIVE_OBJECT_UPDATE_REWRITE_TAIL_EVIDENCE_ENTRY_LIMIT;
        const MAX_UNRESOLVED_SOURCE_BITS: usize = 64;

        let source_fragment_bit_count = source_bits.len();
        let unresolved = source_bits.get(anchored_source_bit_cursor..)?;
        if unresolved.is_empty() || unresolved.len() > MAX_UNRESOLVED_SOURCE_BITS {
            return None;
        }

        let focus_object_id = read_u32_le(live_bytes, focus_offset.saturating_add(2));
        let mut candidates = [None; LIVE_OBJECT_UPDATE_TERMINAL_FRAGMENT_REPLAY_CANDIDATE_LIMIT];
        let mut candidate_count = 0usize;

        // This is correlation evidence only. It searches a bounded set of
        // already committed ledger rows for an exact replay of each complete
        // source span inside the stock-reader residual. A matching bit pattern
        // cannot by itself own, erase, or advance the terminal fragment.
        for entry in self.recent_entries(RECENT_LEDGER_ENTRY_LIMIT).iter().rev() {
            let prior_source_bits = self.source_values_for_entry(source_bits, entry);
            if prior_source_bits.is_empty() || prior_source_bits.len() > unresolved.len() {
                continue;
            }
            let Some(last_replay_start) =
                source_fragment_bit_count.checked_sub(prior_source_bits.len())
            else {
                continue;
            };
            for replay_start in anchored_source_bit_cursor..=last_replay_start {
                let replay_end = replay_start.saturating_add(prior_source_bits.len());
                if source_bits.get(replay_start..replay_end) != Some(prior_source_bits) {
                    continue;
                }

                let prior_object_id = read_u32_le(live_bytes, entry.offset.saturating_add(2));
                let candidate = LiveObjectUpdateTerminalFragmentReplayCandidateEvidence {
                    prior_offset: entry.offset,
                    prior_record_end: entry.record_end,
                    prior_opcode: entry.opcode,
                    prior_marker: entry.marker,
                    prior_object_id,
                    focus_offset,
                    focus_object_id,
                    same_object: prior_object_id.is_some() && prior_object_id == focus_object_id,
                    immediately_precedes_focus: entry.record_end == focus_offset,
                    prior_source_bit_start: entry.source_bit_start,
                    prior_source_bit_end: entry.source_bit_end,
                    prior_source_bit_count: prior_source_bits.len(),
                    unresolved_prefix: live_object_rewrite_bit_slice_evidence(
                        anchored_source_bit_cursor,
                        replay_start,
                        source_bits
                            .get(anchored_source_bit_cursor..replay_start)
                            .unwrap_or(&[]),
                    ),
                    replayed_source_bits: live_object_rewrite_bit_slice_evidence(
                        replay_start,
                        replay_end,
                        source_bits.get(replay_start..replay_end).unwrap_or(&[]),
                    ),
                    unresolved_suffix: live_object_rewrite_bit_slice_evidence(
                        replay_end,
                        source_fragment_bit_count,
                        source_bits.get(replay_end..).unwrap_or(&[]),
                    ),
                };
                if let Some(slot) = candidates.get_mut(candidate_count) {
                    *slot = Some(candidate);
                }
                candidate_count = candidate_count.saturating_add(1);
            }
        }

        let candidates_retained =
            candidate_count.min(LIVE_OBJECT_UPDATE_TERMINAL_FRAGMENT_REPLAY_CANDIDATE_LIMIT);
        Some(LiveObjectUpdateTerminalFragmentHandoffCorrelationEvidence {
            anchored_source_bit_cursor,
            source_fragment_bit_count,
            unresolved_source_bits: live_object_rewrite_bit_slice_evidence(
                anchored_source_bit_cursor,
                source_fragment_bit_count,
                unresolved,
            ),
            candidate_count,
            candidates_retained,
            ambiguity_count: candidate_count.saturating_sub(1),
            candidates,
        })
    }
}

fn format_bit_values_preview(bits: &[bool]) -> String {
    const MAX_PREVIEW_BITS: usize = 32;
    let preview_end = bits.len().min(MAX_PREVIEW_BITS);
    let suffix = if bits.len() > preview_end {
        format!("...+{}", bits.len() - preview_end)
    } else {
        String::new()
    };
    format!(
        "len={} values={:?}{suffix}",
        bits.len(),
        &bits[..preview_end]
    )
}

pub(super) fn live_object_rewrite_bit_slice_evidence(
    bit_start: usize,
    bit_end: usize,
    values: &[bool],
) -> LiveObjectUpdateRewriteBitSliceEvidence {
    let mut bits = [None; LIVE_OBJECT_UPDATE_REWRITE_BIT_PREVIEW_LIMIT];
    for (slot, value) in bits.iter_mut().zip(values.iter().copied()) {
        *slot = Some(value);
    }
    LiveObjectUpdateRewriteBitSliceEvidence {
        bit_start,
        bit_end,
        bit_count: bit_end.saturating_sub(bit_start),
        bits_retained: values
            .len()
            .min(LIVE_OBJECT_UPDATE_REWRITE_BIT_PREVIEW_LIMIT),
        bits,
    }
}

fn live_object_rewrite_bit_slice_sub_evidence(
    evidence: LiveObjectUpdateRewriteBitSliceEvidence,
    bit_start: usize,
    bit_end: usize,
) -> LiveObjectUpdateRewriteBitSliceEvidence {
    let mut bits = [None; LIVE_OBJECT_UPDATE_REWRITE_BIT_PREVIEW_LIMIT];
    let bit_count = bit_end.saturating_sub(bit_start);
    let bits_retained = bit_count.min(LIVE_OBJECT_UPDATE_REWRITE_BIT_PREVIEW_LIMIT);
    for (index, slot) in bits.iter_mut().take(bits_retained).enumerate() {
        let absolute_bit = bit_start.saturating_add(index);
        if absolute_bit < evidence.bit_start {
            continue;
        }
        let parent_index = absolute_bit.saturating_sub(evidence.bit_start);
        if parent_index < evidence.bits_retained {
            *slot = evidence.bits[parent_index];
        }
    }
    LiveObjectUpdateRewriteBitSliceEvidence {
        bit_start,
        bit_end,
        bit_count,
        bits_retained,
        bits,
    }
}

fn live_object_rewrite_byte_slice_evidence(
    byte_start: usize,
    byte_end: usize,
    values: &[u8],
) -> LiveObjectUpdateRewriteByteSliceEvidence {
    let mut bytes = [None; LIVE_OBJECT_UPDATE_REWRITE_BYTE_PREVIEW_LIMIT];
    for (slot, value) in bytes.iter_mut().zip(values.iter().copied()) {
        *slot = Some(value);
    }
    LiveObjectUpdateRewriteByteSliceEvidence {
        byte_start,
        byte_end,
        byte_count: byte_end.saturating_sub(byte_start),
        bytes_retained: values
            .len()
            .min(LIVE_OBJECT_UPDATE_REWRITE_BYTE_PREVIEW_LIMIT),
        bytes,
    }
}

fn live_object_item_focus_failure_read_window(
    live_bytes: &[u8],
    offset: usize,
    record_end: usize,
    read_cursor: usize,
) -> LiveObjectUpdateRewriteByteSliceEvidence {
    let row_start = offset.min(live_bytes.len());
    let row_end = record_end.min(live_bytes.len()).max(row_start);
    let clamped = read_cursor.min(row_end).max(row_start);
    let mut byte_start = clamped;
    let mut byte_end = clamped
        .saturating_add(LIVE_OBJECT_UPDATE_REWRITE_BYTE_PREVIEW_LIMIT)
        .min(row_end);
    if byte_start == byte_end && row_end > row_start {
        byte_start = row_end
            .saturating_sub(LIVE_OBJECT_UPDATE_REWRITE_BYTE_PREVIEW_LIMIT)
            .max(row_start);
        byte_end = row_end;
    }
    live_object_rewrite_byte_slice_evidence(
        byte_start,
        byte_end,
        live_bytes.get(byte_start..byte_end).unwrap_or(&[]),
    )
}

fn live_object_item_focus_failure_bit_window(
    fragment_bits: &[bool],
    bit_cursor: usize,
) -> LiveObjectUpdateRewriteBitSliceEvidence {
    let bit_start = bit_cursor.min(fragment_bits.len());
    let bit_end = bit_start
        .saturating_add(LIVE_OBJECT_UPDATE_REWRITE_BIT_PREVIEW_LIMIT)
        .min(fragment_bits.len());
    live_object_rewrite_bit_slice_evidence(
        bit_start,
        bit_end,
        fragment_bits.get(bit_start..bit_end).unwrap_or(&[]),
    )
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct LiveObjectItemUpdateCursorFailure {
    kind: LiveObjectUpdateRewriteFailureKind,
    offset: usize,
    record_end: usize,
    bit_cursor: usize,
    focus_failure: Option<item::ItemUpdateCursorFailure>,
    focus_cursor_ledger: LiveObjectUpdateItemCursorLedgerEvidence,
    focus_failure_read_window: Option<LiveObjectUpdateRewriteByteSliceEvidence>,
    focus_failure_bit_window: Option<LiveObjectUpdateRewriteBitSliceEvidence>,
    unowned_neighbor: Option<LiveObjectItemUpdateUnownedNeighbor>,
    contiguous_tail: Option<LiveObjectUpdateRewriteTailEvidence>,
    source_window: Option<LiveObjectUpdateSourceWindowEvidence>,
}

impl LiveObjectItemUpdateCursorFailure {
    fn into_rewrite_failure(self) -> LiveObjectUpdateRewriteFailure {
        LiveObjectUpdateRewriteFailure {
            reason: self.kind.as_str(),
            kind: self.kind,
            offset: self.offset,
            record_end: self.record_end,
            bit_cursor: self.bit_cursor,
            terminal_door_placeable_tail9_residual: None,
            item_update_neighbor_gap_origin: self
                .unowned_neighbor
                .map(|neighbor| neighbor.gap_origin),
            item_update_cursor_evidence: Some(self.evidence()),
        }
    }

    fn evidence(self) -> LiveObjectUpdateItemCursorFailureEvidence {
        let focus = self
            .focus_failure
            .map(|failure| {
                (
                    failure.stage.as_str(),
                    failure.mask,
                    failure.read_cursor,
                    failure.bit_cursor,
                    failure.orientation_vector,
                )
            })
            .or_else(|| {
                self.unowned_neighbor.map(|neighbor| {
                    (
                        neighbor.focus_failure_stage,
                        neighbor.focus_failure_mask,
                        neighbor.focus_failure_read_cursor,
                        neighbor.focus_failure_bit_cursor,
                        neighbor.focus_failure_orientation_vector,
                    )
                })
            })
            .unwrap_or(("none", None, self.offset, self.bit_cursor, None));
        let item_handoff = self
            .unowned_neighbor
            .map(|neighbor| self.item_handoff_evidence(neighbor));
        LiveObjectUpdateItemCursorFailureEvidence {
            focus_failure_stage: focus.0,
            focus_failure_mask: focus.1,
            focus_failure_read_cursor: focus.2,
            focus_failure_bit_cursor: focus.3,
            focus_failure_orientation_vector: focus.4,
            focus_cursor_ledger: Some(self.focus_cursor_ledger),
            focus_failure_read_window: self.focus_failure_read_window,
            focus_failure_bit_window: self.focus_failure_bit_window,
            unowned_neighbor: self.unowned_neighbor.map(|neighbor| {
                LiveObjectUpdateItemUnownedNeighborEvidence {
                    delta: neighbor.delta,
                    bit_start: neighbor.bit_start,
                    bit_end: neighbor.bit_end,
                    read_end: neighbor.read_end,
                    translated_mask: neighbor.translated_mask,
                    orientation_vector: neighbor.orientation_vector,
                    emitted_gap_bits: neighbor.emitted_gap_bits,
                    emitted_gap_bit_start: neighbor.emitted_gap_bit_start,
                    emitted_gap_bit_end: neighbor.emitted_gap_bit_end,
                    emitted_gap_values: neighbor.emitted_gap_values,
                    source_gap_bits: neighbor.source_gap_bits,
                    source_gap_bit_start: neighbor.source_gap_bit_start,
                    source_gap_bit_end: neighbor.source_gap_bit_end,
                    source_gap_values: neighbor.source_gap_values,
                    previous_offset: neighbor.previous_offset,
                    previous_record_end: neighbor.previous_record_end,
                    previous_family: neighbor.previous_family,
                    gap_origin: neighbor.gap_origin,
                    source_owner: neighbor.source_owner,
                }
            }),
            item_handoff,
            contiguous_tail: self.contiguous_tail,
            source_window: self.source_window,
        }
    }

    fn item_handoff_evidence(
        self,
        neighbor: LiveObjectItemUpdateUnownedNeighbor,
    ) -> LiveObjectUpdateItemHandoffEvidence {
        let focus_entry = self.source_window.and_then(|source_window| {
            source_window
                .entries
                .iter()
                .flatten()
                .copied()
                .find(|entry| {
                    entry.offset == self.offset
                        && entry.record_end == self.record_end
                        && entry.opcode == b'U'
                        && entry.marker == ITEM_OBJECT_TYPE
                })
        });
        let classification = live_object_item_handoff_classification(
            self.source_window,
            self.offset,
            self.record_end,
            neighbor,
        );

        LiveObjectUpdateItemHandoffEvidence {
            previous_offset: neighbor.previous_offset,
            previous_record_end: neighbor.previous_record_end,
            previous_family: neighbor.previous_family,
            focus_offset: self.offset,
            focus_record_end: self.record_end,
            focus_bit_cursor: self.bit_cursor,
            focus_update_mask: focus_entry.and_then(|entry| entry.update_mask),
            focus_source_bits: focus_entry.map(|entry| entry.source_bits),
            focus_prefix: neighbor.focus_prefix,
            prefix_source_replay: live_object_item_handoff_prefix_source_replay(
                neighbor.focus_prefix,
                neighbor.source_gap_values,
                neighbor.source_gap_bits,
                neighbor.emitted_gap_bits,
            ),
            focus_cursor_ledger: self.focus_cursor_ledger,
            neighbor_delta: neighbor.delta,
            neighbor_bit_start: neighbor.bit_start,
            neighbor_bit_end: neighbor.bit_end,
            neighbor_read_end: neighbor.read_end,
            neighbor_translated_mask: neighbor.translated_mask,
            neighbor_orientation_vector: neighbor.orientation_vector,
            gap_origin: neighbor.gap_origin,
            source_owner: neighbor.source_owner,
            emitted_gap_bits: neighbor.emitted_gap_bits,
            emitted_gap_bit_start: neighbor.emitted_gap_bit_start,
            emitted_gap_bit_end: neighbor.emitted_gap_bit_end,
            emitted_gap_values: neighbor.emitted_gap_values,
            source_gap_bits: neighbor.source_gap_bits,
            source_gap_bit_start: neighbor.source_gap_bit_start,
            source_gap_bit_end: neighbor.source_gap_bit_end,
            source_gap_values: neighbor.source_gap_values,
            sequence_kind: classification.sequence_kind,
            source_contract: classification.source_contract,
            source_decision: classification.source_decision,
            sequence_context: classification.sequence_context,
            sequence_residue: classification.sequence_residue,
        }
    }
}

